mapper.sql:
/*미결합주문*/ SELECT DT.OWKEY /*화주코드*/ , VHD.CTKEY , DT.ICKEY /*제품코드*/ , DT.ICUTKEY /*제품단위코드*/ , VHD.OR_TYPE_CD , OT.OR_TYPE_NAME , DT.INITQTY /*초기수량*/ , DT.EXQTY /*예정수량*/ , DT.CFQTY /*확정수량*/ , DT.UOM /*주문단위*/ , COALESCE(DT.INDIAMT, 0) + COALESCE(DT.VAT, 0) AS SALEPRICE /*부가세*/ , DT.OB_COSTPRICE /*출고단가*/ , DT.INDIAMT /*지시금액*/ , COALESCE(DT.VAT, 0) AS VAT , DT.PRODUCT_DT /*생산일자*/ , DT.PRODUCT_LOT /*생산 LOT*/ , DT.SOHDKEY /*S/O번호*/ , DT.SODTKEY /*S/O상세번호*/ , '00' AS WKSTATUS /*작업(주문) 상태*/ , DT.EXTERNORDERKEY /*외부주문번호*/ , DT.EXTERNORDERDETAILKEY /*외부주문상세번호*/ , DT.ICGRKEY /*상품그룹*/ , DT.ICGRTYPE /*상품그룹유형*/ , VHD.ACKEY , DT.LOGGRPCD , DT.IC_RATE /*행사상품비율*/ , DT.BONUS_IC_RATE /*덤상품비율*/ , DT.SPEC , VHD.DELIVERY_KEY , DT.WEIGHTUNIT /*중량단위*/ , CASE WHEN DT.WEIGHTUNIT ='G' THEN COALESCE(DT.TOTALWEIGHT, 0) WHEN DT.WEIGHTUNIT ='KG' THEN COALESCE(DT.TOTALWEIGHT, 0) * 1000 WHEN DT.WEIGHTUNIT ='MT' THEN COALESCE(DT.TOTALWEIGHT, 0) * 1000000 ELSE DT.TOTALWEIGHT END TOTALWEIGHT /*총중량*/ , CASE WHEN DT.VOLUMEUNIT = 'MM' THEN COALESCE(DT.VOLUME, 0) /*총부피*/ WHEN DT.VOLUMEUNIT = 'ML' THEN COALESCE(DT.VOLUME, 0) * 1000 WHEN DT.VOLUMEUNIT = 'M3' THEN COALESCE(DT.VOLUME, 0) * 1000000000 ELSE DT.VOLUME END AS VOLUME /*총부피*/ , DT.VOLUMEUNIT /*부피단위*/ , DT.CONTROL_PROCESS_YN /*주문통제처리여부*/ , #{userid} AS INSERTURKEY /*입력사용자ID*/ , #{userid} AS UPDATEURKEY /*수정사용자ID*/ FROM TORDER_INFO_SO_DT DT
INNER JOIN (
SELECT #{item.soHdkey} AS SOHDKEY , #{item.ctkey} AS CTKEY , #{item.ackey} AS ACKEY , #{item.owkey} AS OWKEY , #{item.orTypeCd} AS OR_TYPE_CD , #{item.deliveryKey} AS DELIVERY_KEY
) VHD ON DT.SOHDKEY = VHD.SOHDKEY AND DT.OWKEY = VHD.OWKEY
INNER JOIN TORDER_MST_ORTYPE OT ON VHD.OWKEY = OT.OWKEY AND VHD.OR_TYPE_CD = OT.OR_TYPE_CD WHERE DT.OWKEY =#{owkey} AND COALESCE(DT.CONTROL_PROCESS_YN, 'N') ='N' /*통제처리여부*/ AND OT.COMBINATIONYN='N' /*미결합주문 조건1:결합여부*/ AND (OT.OWSPCVERIFICATION IS NULL OR OT.OWSPCVERIFICATION<>'MULTIPLE') /*미결합주문 조건2:덤행사*/ UNION ALL /*결합주문*/ SELECT DT.OWKEY /*화주코드*/ , VHD.CTKEY , DT.ICKEY /*제품코드*/ , DT.ICUTKEY /*제품단위코드*/ , VHD.OR_TYPE_CD , OT.OR_TYPE_NAME , SUM(DT.INITQTY) AS INITQTY /*초기수량*/ , SUM(DT.EXQTY) AS EXQTY /*예정수량*/ , SUM(DT.CFQTY) AS CFQTY /*확정수량*/ , F.ICUTTYPE AS UOM /*주문단위*/ , SUM(COALESCE(DT.INDIAMT, 0) + COALESCE(DT.VAT, 0)) AS SALEPRICE /*부가세*/ , MAX(DT.OB_COSTPRICE) AS OB_COSTPRICE /*출고단가*/ , SUM(COALESCE(DT.INDIAMT, 0)) AS INDIAMT /*지시금액*/ , SUM(COALESCE(DT.VAT, 0)) AS VAT , DT.PRODUCT_DT /*생산일자*/ , DT.PRODUCT_LOT /*생산 LOT*/ , DT.SOHDKEY /*S/O번호*/ , CAST(VDD.MAXDTKEY AS NUMERIC) + (ROW_NUMBER() OVER(ORDER BY MIN(DT.SODTKEY) ) * 10) /*S/O상세번호*/ , '00' AS WKSTATUS /*작업(주문) 상태*/ , DT.EXTERNORDERKEY /*외부주문번호*/ , MIN(DT.EXTERNORDERDETAILKEY) AS EXTERNORDERDETAILKEY /*외부주문상세번호*/ , DT.ICGRKEY /*상품그룹*/ , DT.ICGRTYPE /*상품그룹유형*/ , VHD.ACKEY , DT.LOGGRPCD , DT.IC_RATE * IU.ICUNITQTY AS IC_RATE /*행사상품비율(주문입수량적용)*/ , DT.BONUS_IC_RATE * IU.ICUNITQTY AS BONUS_IC_RATE /*덤상품비율(주문입수량적용)*/ , DT.SPEC , VHD.DELIVERY_KEY , DT.WEIGHTUNIT /*중량단위*/ , CASE WHEN DT.WEIGHTUNIT ='G' THEN SUM(COALESCE(DT.TOTALWEIGHT, 0)) WHEN DT.WEIGHTUNIT ='KG' THEN SUM(COALESCE(DT.TOTALWEIGHT, 0)) * 1000 WHEN DT.WEIGHTUNIT ='MT' THEN SUM(COALESCE(DT.TOTALWEIGHT, 0)) * 1000000 ELSE SUM(DT.TOTALWEIGHT) END TOTALWEIGHT /*총중량*/ , CASE WHEN DT.VOLUMEUNIT = 'MM' THEN SUM(COALESCE(DT.VOLUME, 0)) /*총부피*/ WHEN DT.VOLUMEUNIT = 'ML' THEN SUM(COALESCE(DT.VOLUME, 0)) * 1000 WHEN DT.VOLUMEUNIT = 'M3' THEN SUM(COALESCE(DT.VOLUME, 0)) * 1000000000 ELSE SUM(DT.VOLUME) END AS VOLUME /*총부피*/ , DT.VOLUMEUNIT /*부피단위*/ , DT.CONTROL_PROCESS_YN /*주문통제처리여부*/ , #{userid} AS INSERTURKEY /*입력사용자ID*/ , #{userid} AS UPDATEURKEY /*수정사용자ID*/ FROM TORDER_INFO_SO_DT DT
INNER JOIN (
SELECT #{item.soHdkey} AS SOHDKEY , #{item.ctkey} AS CTKEY , #{item.ackey} AS ACKEY , #{item.owkey} AS OWKEY , #{item.orTypeCd} AS OR_TYPE_CD , #{item.deliveryKey} AS DELIVERY_KEY
) VHD ON DT.SOHDKEY = VHD.SOHDKEY AND DT.OWKEY = VHD.OWKEY INNER JOIN ( SELECT SH.OWKEY , SH.SOHDKEY , MAX(SD.SODTKEY) AS MAXDTKEY FROM (
SELECT #{item.soHdkey} AS SOHDKEY , #{item.owkey} AS OWKEY
) SH JOIN TORDER_INFO_SO_DT SD ON SH.OWKEY = SD.OWKEY AND SH.SOHDKEY = SD.SOHDKEY GROUP BY SH.OWKEY , SH.SOHDKEY ) VDD ON DT.SOHDKEY = VDD.SOHDKEY AND DT.OWKEY = VDD.OWKEY
INNER JOIN TORDER_MST_ORTYPE OT ON VHD.OWKEY = OT.OWKEY AND VHD.OR_TYPE_CD = OT.OR_TYPE_CD INNER JOIN TADMIN_MST_ICUTXTYPE IU ON DT.OWKEY = IU.OWKEY AND DT.ICUTKEY = IU.ICUNITKEY AND DT.UOM = IU.ICUNITTYPE INNER JOIN ( SELECT WU.OWKEY, WU.ICUTKEY, WU.CTKEY , (ARRAY_AGG(WU.ICUTTYPE ORDER BY WU.ICUTQTY, WU.VOLUME, WU.ICUTORDER DESC))[array_upper(ARRAY_AGG(WU.ICUTTYPE ORDER BY WU.ICUTQTY, WU.VOLUME, WU.ICUTORDER DESC), 1)] AS ICUTTYPE , (ARRAY_AGG(WU.ICUTQTY ORDER BY WU.ICUTQTY, WU.VOLUME, WU.ICUTORDER DESC))[array_upper(ARRAY_AGG(WU.ICUTQTY ORDER BY WU.ICUTQTY, WU.VOLUME, WU.ICUTORDER DESC), 1)] AS ICUTQTY FROM TWORK_MST_ICUTXTYPE WU WHERE WU.OWKEY = #{owkey} AND WU.OUTBOUNDUSEYN ='Y' GROUP BY WU.OWKEY, WU.ICUTKEY, WU.CTKEY ) F ON DT.OWKEY =F.OWKEY AND DT.ICUTKEY= F.ICUTKEY AND VHD.CTKEY =F.CTKEY WHERE DT.OWKEY =#{owkey} AND COALESCE(DT.CONTROL_PROCESS_YN, 'N') ='N' /*통제처리여부*/ AND (OT.COMBINATIONYN='Y' OR OT.OWSPCVERIFICATION='MULTIPLE') /*결합여부, 덤행사여부*/ GROUP BY DT.OWKEY /*화주코드*/ , VHD.CTKEY , DT.ICKEY /*제품코드*/ , DT.ICUTKEY /*제품단위코드*/ , VHD.OR_TYPE_CD , OT.OR_TYPE_NAME , F.ICUTTYPE /*주문단위*/ , DT.PRODUCT_DT /*생산일자*/ , DT.PRODUCT_LOT /*생산 LOT*/ , DT.SOHDKEY /*S/O번호*/ , VDD.MAXDTKEY , DT.EXTERNORDERKEY /*외부주문번호*/ , DT.ICGRKEY /*상품그룹*/ , DT.ICGRTYPE /*상품그룹유형*/ , VHD.ACKEY , DT.LOGGRPCD , DT.IC_RATE /*행사상품비율*/ , DT.BONUS_IC_RATE /*덤상품비율*/ , IU.ICUNITQTY , DT.SPEC , VHD.DELIVERY_KEY , DT.WEIGHTUNIT /*중량단위*/ , DT.VOLUMEUNIT /*부피단위*/ , DT.CONTROL_PROCESS_YN /*주문통제처리여부*/

mapper.select:
/* oms-socommon-sql-oracle.xml selectInValidateSoHd */ SELECT T.* , CASE WHEN T.ERRCOL IS NULL THEN 1 ELSE 0 END AS IS_SUCCESS , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.ERROR_COLUMN END AS ERROR_COLUMN , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.MESSAGE_CODE END AS ERROR_CODE , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.PARAM END AS ERROR_PARAM , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE REPLACE(REPLACE(COALESCE(MM.DISPLAYMSG, EL.SERVER_MESSAGE), #{param1}, COALESCE(ML.DISPLAYMSG, EL.PARAM)), #{param0}, COALESCE(ML.DISPLAYMSG, EL.PARAM)) END AS SERVER_MESSAGE FROM ( SELECT O.* , CASE WHEN O.ACKEY IS NULL THEN (SELECT X.CTNM FROM TORDER_MST_CT X WHERE X.CTKEY = O.FROMTOCTKEY) ELSE AC.ACNM END AS ACNM , CASE WHEN O.OWKEY IS NULL AND CHK.OWKEY > 0 THEN 'OWKEY' WHEN O.SOHDKEY IS NULL AND CHK.SOHDKEY > 0 THEN 'SOHDKEY' WHEN O.DLVYEXPCTDAY IS NULL AND CHK.DLVYEXPCTDAY > 0 THEN 'DLVYEXPCTDAY' WHEN O.ORDERISTDAY IS NULL AND CHK.ORDERISTDAY > 0 THEN 'ORDERISTDAY' WHEN O.ORDERTYPECD IS NULL AND CHK.ORDERTYPECD > 0 THEN 'ORDERTYPECD' WHEN O.WKSTATUS IS NULL AND CHK.WKSTATUS > 0 THEN 'WKSTATUS' WHEN O.CTKEY IS NULL AND CHK.CTKEY > 0 THEN 'CTKEY' WHEN O.DLVYACKEY IS NULL AND CHK.DLVYACKEY > 0 THEN 'DLVYACKEY' WHEN O.STOREKEY IS NULL AND CHK.STOREKEY > 0 THEN 'STOREKEY' WHEN O.BILLKEY IS NULL AND CHK.BILLKEY > 0 THEN 'BILLKEY' WHEN O.PAYERKEY IS NULL AND CHK.PAYERKEY > 0 THEN 'PAYERKEY' WHEN O.ACKEY IS NULL AND CHK.ACKEY > 0 THEN 'ACKEY' WHEN O.LOGGRPCD IS NULL AND CHK.LOGGRPCD > 0 THEN 'LOGGRPCD' WHEN O.ORGORDERKEY IS NULL AND CHK.ORGORDERKEY > 0 THEN 'ORGORDERKEY' WHEN O.FROMTOCTKEY IS NULL AND CHK.FROMTOCTKEY > 0 THEN 'FROMTOCTKEY' WHEN O.ICGRTYPE IS NULL AND CHK.ICGRTYPE > 0 THEN 'ICGRTYPE' WHEN O.ICGRKEY IS NULL AND CHK.ICGRKEY > 0 THEN 'ICGRKEY' WHEN O.POTYPE IS NULL AND CHK.POTYPE > 0 THEN 'POTYPE' WHEN O.RFRNCKEY IS NULL AND CHK.RFRNKEY > 0 THEN 'RFRNKEY' WHEN O.SALESEMPID IS NULL AND CHK.SALESEMPID > 0 THEN 'SALESEMPID' WHEN O.DLVYEMPID IS NULL AND CHK.DLVYEMPID > 0 THEN 'DLVYEMPID' WHEN O.EDIYN IS NULL AND CHK.EDIYN > 0 THEN 'EDIYN' WHEN O.CMT IS NULL AND CHK.CMT > 0 THEN 'CMT' WHEN O.ADDCMT01 IS NULL AND CHK.ADDCMT01 > 0 THEN 'ADDCMT01' WHEN O.ADDCMT02 IS NULL AND CHK.ADDCMT01 > 0 THEN 'ADDCMT02' WHEN O.CNLYN IS NULL AND CHK.CNLYN > 0 THEN 'CNLYN' WHEN O.CNLDATE IS NULL AND CHK.CNLDATE > 0 THEN 'CNLDATE' WHEN O.CNLEMPID IS NULL AND CHK.CNLEMPID > 0 THEN 'CNLEMPID' WHEN O.ORDERSNDYN IS NULL AND CHK.ORDERSNDYN > 0 THEN 'ORDERSNDYN' WHEN O.ORDERSNDDATE IS NULL AND CHK.ORDERSNDDATE > 0 THEN 'ORDERSNDDATE' WHEN O.ORDERSNDUSERID IS NULL AND CHK.ORDERSNDUSERID > 0 THEN 'ORDERSNDUSERID' WHEN O.COHDKEY IS NULL AND CHK.COHDKEY > 0 THEN 'COHDKEY' WHEN O.EXTORDERTYPECD IS NULL AND CHK.EXTORDERTYPECD > 0 THEN 'EXTORDERTYPECD' WHEN O.ORDERERRCD IS NULL AND CHK.ORDERERRCD > 0 THEN 'ORDERERRCD' WHEN O.ORDERERRCMT IS NULL AND CHK.ORDERERRCMT > 0 THEN 'ORDERERRCMT' WHEN O.ORDERRSNCD IS NULL AND CHK.ORDERRSNCD > 0 THEN 'ORDERRSNCD' WHEN O.RECPNM IS NULL AND CHK.RECPNM > 0 THEN 'RECPNM' WHEN O.RECPADDRHD IS NULL AND CHK.RECPADDRHD > 0 THEN 'RECPADDRHD' WHEN O.RECPADDRDT IS NULL AND CHK.RECPADDRDT > 0 THEN 'RECPADDRDT' WHEN O.RECPZIPCD IS NULL AND CHK.RECPZIPCD > 0 THEN 'RECPZIPCD' WHEN O.RECPTEL01 IS NULL AND CHK.RECPTEL01 > 0 THEN 'RECPTEL01' WHEN O.RECPTEL02 IS NULL AND CHK.RECPTEL02 > 0 THEN 'RECPTEL02' WHEN O.BUYER IS NULL AND CHK.BUYER > 0 THEN 'BUYER' WHEN O.BUYERADDRHD IS NULL AND CHK.BUYERADDRHD > 0 THEN 'BUYERADDRHD' WHEN O.BUYERADDRDT IS NULL AND CHK.BUYERADDRDT > 0 THEN 'BUYERADDRDT' WHEN O.BUYERZIPCD IS NULL AND CHK.BUYERZIPCD > 0 THEN 'BUYERZIPCD' WHEN O.BUYERTEL01 IS NULL AND CHK.BUYERTEL01 > 0 THEN 'BUYERTEL01' WHEN O.BUYERTEL02 IS NULL AND CHK.BUYERTEL02 > 0 THEN 'BUYERTEL02' WHEN O.RECALLER IS NULL AND CHK.RECALLER > 0 THEN 'RECALLER' WHEN O.RECALLERADDRHD IS NULL AND CHK.RECALLERADDRHD > 0 THEN 'RECALLERADDRHD' WHEN O.RECALLERADDRDT IS NULL AND CHK.RECALLERADDRDT > 0 THEN 'RECALLERADDRDT' WHEN O.RECALLERZIPCD IS NULL AND CHK.RECALLERZIPCD > 0 THEN 'RECALLERZIPCD' WHEN O.RECALLERTEL01 IS NULL AND CHK.RECALLERTEL01 > 0 THEN 'RECALLERTEL01' WHEN O.RECALLERTEL02 IS NULL AND CHK.RECALLERTEL02 > 0 THEN 'RECALLERTEL02' WHEN O.RECALLERIYN IS NULL AND CHK.RECALLERIYN > 0 THEN 'RECALLERIYN' WHEN O.RIRSNCD IS NULL AND CHK.RIRSNCD > 0 THEN 'RIRSNCD' WHEN O.CLAIMNO IS NULL AND CHK.CLAIMNO > 0 THEN 'CLAIMNO' WHEN O.DLVYMETHDCD IS NULL AND CHK.DLVYMETHDCD > 0 THEN 'DLVYMETHDCD' WHEN O.DLVYMETHDDTCD IS NULL AND CHK.DLVYMETHDDTCD > 0 THEN 'DLVYMETHDDTCD' WHEN O.MALORDERDIV IS NULL AND CHK.MALORDERDIV > 0 THEN 'MALORDERDIV' WHEN O.NISYN IS NULL AND CHK.NISYN > 0 THEN 'NISYN' WHEN O.NISCNLRNGDIV IS NULL AND CHK.NISCNLRNGDIV > 0 THEN 'NISCNLRNGDIV' WHEN O.PAYMTCOMPLDAY IS NULL AND CHK.PAYMTCOMPLDAY > 0 THEN 'PAYMTCOMPLDAY' WHEN O.PARTERID IS NULL AND CHK.PARTERID > 0 THEN 'PARTERID' WHEN O.ACCESSKEY IS NULL AND CHK.ACCESSKEY > 0 THEN 'ACCESSKEY' WHEN O.SHMISTNO IS NULL AND CHK.SHMISTNO > 0 THEN 'SHMISTNO' WHEN CHK.DLVYACKEY > 0 AND DC.ACKEY IS NULL THEN 'DLVYACKEY_M' WHEN CHK.STOREKEY > 0 AND SC.ACKEY IS NULL THEN 'STOREKEY_M' WHEN CHK.ACKEY > 0 AND AC.ACKEY IS NULL THEN 'ACKEY_M' WHEN OC.ORDERTYPECD IS NULL THEN 'ORDERTYPECD_M2' WHEN CHK.CTKEY > 0 AND CT.CTKEY IS NULL THEN 'CTKEY_M' WHEN CHK.FROMTOCTKEY > 0 AND TCT.CTKEY IS NULL THEN 'FROMTOCTKEY_M' ELSE NULL END AS ERRCOL FROM (
SELECT SH.*
, '09' AS ORGCTKEY
FROM ( SELECT REQORDERNO, CLAIMNO -- DLVYEXPCTDAY FROM TORDER_INTF_IBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TC ON (TI.REQORDERNO = TC.REQORDERNO OR TI.CLAIMNO = TC.CLAIMNO) --AND TI.DLVYEXPCTDAY = TC.DLVYEXPCTDAY AND TC.IFID = #{interfaceId} AND TC.OWKEY = #{owkey} JOIN TORDER_INFO_SO_HD SH ON TC.OWKEY = SH.OWKEY AND TC.COHDKEY = SH.COHDKEY AND SH.WKSTATUS NOT IN ( #{cancelWkstatus}, #{failWkstatus})
SELECT #{item.owkey} AS OWKEY /*화주코드*/ , #{item.sohdkey} AS SOHDKEY /*S/O번호*/ , #{item.dlvyexpctday} AS DLVYEXPCTDAY /*배송예정일자*/ , #{item.orderistday} AS ORDERISTDAY /*지시일자*/ , #{item.ordertypecd} AS ORDERTYPECD /*주문오더유형*/ , #{item.wkstatus} AS WKSTATUS /*작업(주문) 상태*/ , #{item.ctkey} AS CTKEY /*센터코드*/ , #{item.dlvyackey} AS DLVYACKEY /*납품처코드*/ , #{item.storekey} AS STOREKEY /*판매처코드*/ , #{item.billkey} AS BILLKEY /*정산처코드*/ , #{item.payerkey} AS PAYERKEY /*청구처코드*/ , #{item.ackey} AS ACKEY /*공급처코드*/ , #{item.loggrpcd} AS LOGGRPCD /*상/저온 구분*/ , #{item.orgorderkey} AS ORGORDERKEY /*외부주문번호*/ , #{item.fromtoctkey} AS FROMTOCTKEY /*물품 이동 센터*/ , #{item.icgrtype} AS ICGRTYPE /*물품그룹유형*/ , #{item.icgrkey} AS ICGRKEY /*물품그룹코드*/ , #{item.potype} AS POTYPE /*PO타입*/ , #{item.rfrnckey} AS RFRNCKEY /*이전참조문서번호*/ , #{item.salesempid} AS SALESEMPID /*영업사원ID*/ , #{item.dlvyempid} AS DLVYEMPID /*배송사원ID*/ , #{item.ediyn} AS EDIYN /*EDI 등록 여부*/ , #{item.cmt} AS CMT /*비고*/ , #{item.addcmt01} AS ADDCMT01 /*추가비고*/ , #{item.addcmt02} AS ADDCMT02 /*추가비고*/ , #{item.cnlyn} AS CNLYN /*주문취소여부*/ , #{item.cnldate} AS CNLDATE /*주문취소일시*/ , #{item.cnlempid} AS CNLEMPID /*주문취소ID*/ , #{item.ordersndyn} AS ORDERSNDYN /*주문전송여부*/ , #{item.ordersnddate} AS ORDERSNDDATE /*주문전송일시*/ , #{item.ordersnduserid} AS ORDERSNDUSERID /*주문전송ID*/ , #{item.cohdkey} AS COHDKEY /*CO주문번호*/ , #{item.extordertypecd} AS EXTORDERTYPECD /*CO주문번호*/ , #{item.ordererrcd} AS ORDERERRCD /*주문오류 코드*/ , #{item.ordererrcmt} AS ORDERERRCMT /*주문생성 오류비고*/ , #{item.orderrsncd} AS ORDERRSNCD /*주문생성 오류비고*/ , #{item.recpnm} AS RECPNM , #{item.recpaddrhd} AS RECPADDRHD , #{item.recpaddrdt} AS RECPADDRDT , #{item.recpzipcd} AS RECPZIPCD , #{item.recptel01} AS RECPTEL01 , #{item.recptel02} AS RECPTEL02 , #{item.buyer} AS BUYER , #{item.buyeraddrhd} AS BUYERADDRHD , #{item.buyeraddrdt} AS BUYERADDRDT , #{item.buyerzipcd} AS BUYERZIPCD , #{item.buyertel01} AS BUYERTEL01 , #{item.buyertel02} AS BUYERTEL02 , #{item.recaller} AS RECALLER , #{item.recalleraddrhd} AS RECALLERADDRHD , #{item.recalleraddrdt} AS RECALLERADDRDT , #{item.recallerzipcd} AS RECALLERZIPCD , #{item.recallertel01} AS RECALLERTEL01 , #{item.recallertel02} AS RECALLERTEL02 , #{item.recalleriyn} AS RECALLERIYN , #{item.rirsncd} AS RIRSNCD , #{item.claimno} AS CLAIMNO , #{item.dlvymethdcd} AS DLVYMETHDCD , #{item.dlvymethddtcd} AS DLVYMETHDDTCD , #{item.malorderdiv} AS MALORDERDIV , #{item.nisyn} AS NISYN , #{item.niscnlrngdiv} AS NISCNLRNGDIV , #{item.paymtcomplday} AS PAYMTCOMPLDAY , #{item.parterid} AS PARTERID , #{item.accesskey} AS ACCESSKEY , #{item.shmistno} AS SHMISTNO , #{item.uploadkey} AS UPLOADKEY , #{item.insertdate} AS INSERTDATE /*입력 일시*/ , #{item.inserturkey} AS INSERTURKEY /*입력 사용자 ID*/ , #{item.updatedate} AS UPDATEDATE /*수정 일시*/ , #{item.updateurkey} AS UPDATEURKEY /*수정 사용자 ID*/
) O LEFT JOIN ( SELECT OWKEY , ORDERTYPECD , SUM(CASE WHEN SOCOLUMN='SOHDKEY' THEN 1 ELSE 0 END) AS SOHDKEY , SUM(CASE WHEN SOCOLUMN='DLVYEXPCTDAY' THEN 1 ELSE 0 END) AS DLVYEXPCTDAY , SUM(CASE WHEN SOCOLUMN='ORDERISTDAY' THEN 1 ELSE 0 END) AS ORDERISTDAY , SUM(CASE WHEN SOCOLUMN='WKSTATUS' THEN 1 ELSE 0 END) AS WKSTATUS , SUM(CASE WHEN SOCOLUMN='CTKEY' THEN 1 ELSE 0 END) AS CTKEY , SUM(CASE WHEN SOCOLUMN='DLVYACKEY' THEN 1 ELSE 0 END) AS DLVYACKEY , SUM(CASE WHEN SOCOLUMN='STOREKEY' THEN 1 ELSE 0 END) AS STOREKEY , SUM(CASE WHEN SOCOLUMN='BILLKEY' THEN 1 ELSE 0 END) AS BILLKEY , SUM(CASE WHEN SOCOLUMN='PAYERKEY' THEN 1 ELSE 0 END) AS PAYERKEY , SUM(CASE WHEN SOCOLUMN='ACKEY' THEN 1 ELSE 0 END) AS ACKEY , SUM(CASE WHEN SOCOLUMN='LOGGRPCD' THEN 1 ELSE 0 END) AS LOGGRPCD , SUM(CASE WHEN SOCOLUMN='ORGORDERKEY' THEN 1 ELSE 0 END) AS ORGORDERKEY , SUM(CASE WHEN SOCOLUMN='FROMTOCTKEY' THEN 1 ELSE 0 END) AS FROMTOCTKEY , SUM(CASE WHEN SOCOLUMN='ICGRTYPE' THEN 1 ELSE 0 END) AS ICGRTYPE , SUM(CASE WHEN SOCOLUMN='ICGRKEY' THEN 1 ELSE 0 END) AS ICGRKEY , SUM(CASE WHEN SOCOLUMN='POTYPE' THEN 1 ELSE 0 END) AS POTYPE , SUM(CASE WHEN SOCOLUMN='RFRNKEY' THEN 1 ELSE 0 END) AS RFRNKEY , SUM(CASE WHEN SOCOLUMN='SALESEMPID' THEN 1 ELSE 0 END) AS SALESEMPID , SUM(CASE WHEN SOCOLUMN='DLVYEMPID' THEN 1 ELSE 0 END) AS DLVYEMPID , SUM(CASE WHEN SOCOLUMN='EDIYN' THEN 1 ELSE 0 END) AS EDIYN , SUM(CASE WHEN SOCOLUMN='CMT' THEN 1 ELSE 0 END) AS CMT , SUM(CASE WHEN SOCOLUMN='ADDCMT01' THEN 1 ELSE 0 END) AS ADDCMT01 , SUM(CASE WHEN SOCOLUMN='ADDCMT02' THEN 1 ELSE 0 END) AS ADDCMT02 , SUM(CASE WHEN SOCOLUMN='CNLYN' THEN 1 ELSE 0 END) AS CNLYN , SUM(CASE WHEN SOCOLUMN='CNLDATE' THEN 1 ELSE 0 END) AS CNLDATE , SUM(CASE WHEN SOCOLUMN='CNLEMPID' THEN 1 ELSE 0 END) AS CNLEMPID , SUM(CASE WHEN SOCOLUMN='ORDERSNDYN' THEN 1 ELSE 0 END) AS ORDERSNDYN , SUM(CASE WHEN SOCOLUMN='ORDERSNDDATE' THEN 1 ELSE 0 END) AS ORDERSNDDATE , SUM(CASE WHEN SOCOLUMN='ORDERSNDUSERID' THEN 1 ELSE 0 END) AS ORDERSNDUSERID , SUM(CASE WHEN SOCOLUMN='COHDKEY' THEN 1 ELSE 0 END) AS COHDKEY , SUM(CASE WHEN SOCOLUMN='EXTORDERTYPECD' THEN 1 ELSE 0 END) AS EXTORDERTYPECD , SUM(CASE WHEN SOCOLUMN='ORDERERRCD' THEN 1 ELSE 0 END) AS ORDERERRCD , SUM(CASE WHEN SOCOLUMN='ORDERERRCMT' THEN 1 ELSE 0 END) AS ORDERERRCMT , SUM(CASE WHEN SOCOLUMN='ORDERRSNCD' THEN 1 ELSE 0 END) AS ORDERRSNCD , SUM(CASE WHEN SOCOLUMN='RECPNM' THEN 1 ELSE 0 END) AS RECPNM , SUM(CASE WHEN SOCOLUMN='RECPADDRHD' THEN 1 ELSE 0 END) AS RECPADDRHD , SUM(CASE WHEN SOCOLUMN='RECPADDRDT' THEN 1 ELSE 0 END) AS RECPADDRDT , SUM(CASE WHEN SOCOLUMN='RECPZIPCD' THEN 1 ELSE 0 END) AS RECPZIPCD , SUM(CASE WHEN SOCOLUMN='RECPTEL01' THEN 1 ELSE 0 END) AS RECPTEL01 , SUM(CASE WHEN SOCOLUMN='RECPTEL02' THEN 1 ELSE 0 END) AS RECPTEL02 , SUM(CASE WHEN SOCOLUMN='BUYER' THEN 1 ELSE 0 END) AS BUYER , SUM(CASE WHEN SOCOLUMN='BUYERADDRHD' THEN 1 ELSE 0 END) AS BUYERADDRHD , SUM(CASE WHEN SOCOLUMN='BUYERADDRDT' THEN 1 ELSE 0 END) AS BUYERADDRDT , SUM(CASE WHEN SOCOLUMN='BUYERZIPCD' THEN 1 ELSE 0 END) AS BUYERZIPCD , SUM(CASE WHEN SOCOLUMN='BUYERTEL01' THEN 1 ELSE 0 END) AS BUYERTEL01 , SUM(CASE WHEN SOCOLUMN='BUYERTEL02' THEN 1 ELSE 0 END) AS BUYERTEL02 , SUM(CASE WHEN SOCOLUMN='RECALLER' THEN 1 ELSE 0 END) AS RECALLER , SUM(CASE WHEN SOCOLUMN='RECALLERADDRHD' THEN 1 ELSE 0 END) AS RECALLERADDRHD , SUM(CASE WHEN SOCOLUMN='RECALLERADDRDT' THEN 1 ELSE 0 END) AS RECALLERADDRDT , SUM(CASE WHEN SOCOLUMN='RECALLERZIPCD' THEN 1 ELSE 0 END) AS RECALLERZIPCD , SUM(CASE WHEN SOCOLUMN='RECALLERTEL01' THEN 1 ELSE 0 END) AS RECALLERTEL01 , SUM(CASE WHEN SOCOLUMN='RECALLERTEL02' THEN 1 ELSE 0 END) AS RECALLERTEL02 , SUM(CASE WHEN SOCOLUMN='RECALLERIYN' THEN 1 ELSE 0 END) AS RECALLERIYN , SUM(CASE WHEN SOCOLUMN='RIRSNCD' THEN 1 ELSE 0 END) AS RIRSNCD , SUM(CASE WHEN SOCOLUMN='CLAIMNO' THEN 1 ELSE 0 END) AS CLAIMNO , SUM(CASE WHEN SOCOLUMN='DLVYMETHDCD' THEN 1 ELSE 0 END) AS DLVYMETHDCD , SUM(CASE WHEN SOCOLUMN='DLVYMETHDDTCD' THEN 1 ELSE 0 END) AS DLVYMETHDDTCD , SUM(CASE WHEN SOCOLUMN='MALORDERDIV' THEN 1 ELSE 0 END) AS MALORDERDIV , SUM(CASE WHEN SOCOLUMN='NISYN' THEN 1 ELSE 0 END) AS NISYN , SUM(CASE WHEN SOCOLUMN='NISCNLRNGDIV' THEN 1 ELSE 0 END) AS NISCNLRNGDIV , SUM(CASE WHEN SOCOLUMN='PAYMTCOMPLDAY' THEN 1 ELSE 0 END) AS PAYMTCOMPLDAY , SUM(CASE WHEN SOCOLUMN='PARTERID' THEN 1 ELSE 0 END) AS PARTERID , SUM(CASE WHEN SOCOLUMN='ACCESSKEY' THEN 1 ELSE 0 END) AS ACCESSKEY , SUM(CASE WHEN SOCOLUMN='SHMISTNO' THEN 1 ELSE 0 END) AS SHMISTNO FROM TORDER_INFO_SO_CHK WHERE HDDTDIV = #{hddtdiv} AND DELYN = 'N' AND REQRDYN = 'Y' GROUP BY OWKEY, ORDERTYPECD ) CHK ON O.OWKEY = CHK.OWKEY AND O.ORDERTYPECD = CHK.ORDERTYPECD LEFT JOIN TORDER_MST_AC DC ON O.OWKEY = DC.OWKEY AND O.DLVYACKEY = DC.ACKEY LEFT JOIN TORDER_MST_AC SC ON O.OWKEY = SC.OWKEY AND O.STOREKEY = SC.ACKEY LEFT JOIN TORDER_MST_AC AC ON O.OWKEY = AC.OWKEY AND O.ACKEY = AC.ACKEY LEFT JOIN TORDER_MST_CT CT ON O.CTKEY = CT.CTKEY LEFT JOIN TORDER_MST_CT TCT ON O.FROMTOCTKEY = TCT.CTKEY LEFT JOIN ( SELECT OWKEY , ORDERTYPECD FROM TORDER_MST_ORTYPE WHERE DELYN = 'N'
AND ORDERAT=#{orderat} AND IBYN = #{ibyn} AND OBYN = #{obyn}
) OC ON O.OWKEY = OC.OWKEY AND O.ORDERTYPECD = OC.ORDERTYPECD ) T LEFT JOIN (
) EL ON T.ERRCOL = EL.SOCOLUMN LEFT JOIN TADMIN_MST_MULAAPMSG_DT ML ON EL.PARAM = ML.MULAAPMSGHDKEY AND ML.LAKEY = COALESCE(#{lakey}, 'KOR') LEFT JOIN TADMIN_MST_MULAAPMSG_DT MM ON 'MSG_' || EL.MESSAGE_CODE = MM.MULAAPMSGHDKEY AND MM.LAKEY = COALESCE(#{lakey}, 'KOR') WHERE 1=1

/* oms-socommon-sql-oracle.xml selectOutValidateSoHd */ SELECT T.* , CASE WHEN T.ERRCOL IS NULL THEN 1 ELSE 0 END AS IS_SUCCESS , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.ERROR_COLUMN END AS ERROR_COLUMN , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.MESSAGE_CODE END AS ERROR_CODE , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.PARAM END AS ERROR_PARAM , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE REPLACE(REPLACE(COALESCE(MM.DISPLAYMSG, EL.SERVER_MESSAGE), #{param1}, COALESCE(ML.DISPLAYMSG, EL.PARAM)), #{param0}, COALESCE(ML.DISPLAYMSG, EL.PARAM)) END AS SERVER_MESSAGE FROM ( SELECT O.* , CASE WHEN O.OWKEY IS NULL AND CHK.OWKEY > 0 THEN 'OWKEY' WHEN O.SOHDKEY IS NULL AND CHK.SOHDKEY > 0 THEN 'SOHDKEY' WHEN O.DLVYEXPCTDAY IS NULL AND CHK.DLVYEXPCTDAY > 0 THEN 'DLVYEXPCTDAY' WHEN O.ORDERISTDAY IS NULL AND CHK.ORDERISTDAY > 0 THEN 'ORDERISTDAY' WHEN O.ORDERTYPECD IS NULL AND CHK.ORDERTYPECD > 0 THEN 'ORDERTYPECD' WHEN O.WKSTATUS IS NULL AND CHK.WKSTATUS > 0 THEN 'WKSTATUS' WHEN O.CTKEY IS NULL AND CHK.CTKEY > 0 THEN 'CTKEY' WHEN O.DLVYACKEY IS NULL AND CHK.DLVYACKEY > 0 THEN 'DLVYACKEY' WHEN O.STOREKEY IS NULL AND CHK.STOREKEY > 0 THEN 'STOREKEY' WHEN O.BILLKEY IS NULL AND CHK.BILLKEY > 0 THEN 'BILLKEY' WHEN O.PAYERKEY IS NULL AND CHK.PAYERKEY > 0 THEN 'PAYERKEY' WHEN O.ACKEY IS NULL AND CHK.ACKEY > 0 THEN 'ACKEY' WHEN O.LOGGRPCD IS NULL AND CHK.LOGGRPCD > 0 THEN 'LOGGRPCD' WHEN O.ORGORDERKEY IS NULL AND CHK.ORGORDERKEY > 0 THEN 'ORGORDERKEY' WHEN O.FROMTOCTKEY IS NULL AND CHK.FROMTOCTKEY > 0 THEN 'FROMTOCTKEY' WHEN O.ICGRTYPE IS NULL AND CHK.ICGRTYPE > 0 THEN 'ICGRTYPE' WHEN O.ICGRKEY IS NULL AND CHK.ICGRKEY > 0 THEN 'ICGRKEY' WHEN O.POTYPE IS NULL AND CHK.POTYPE > 0 THEN 'POTYPE' WHEN O.RFRNCKEY IS NULL AND CHK.RFRNKEY > 0 THEN 'RFRNKEY' WHEN O.SALESEMPID IS NULL AND CHK.SALESEMPID > 0 THEN 'SALESEMPID' WHEN O.DLVYEMPID IS NULL AND CHK.DLVYEMPID > 0 THEN 'DLVYEMPID' WHEN O.EDIYN IS NULL AND CHK.EDIYN > 0 THEN 'EDIYN' WHEN O.CMT IS NULL AND CHK.CMT > 0 THEN 'CMT' WHEN O.ADDCMT01 IS NULL AND CHK.ADDCMT01 > 0 THEN 'ADDCMT01' WHEN O.ADDCMT02 IS NULL AND CHK.ADDCMT01 > 0 THEN 'ADDCMT02' WHEN O.CNLYN IS NULL AND CHK.CNLYN > 0 THEN 'CNLYN' WHEN O.CNLDATE IS NULL AND CHK.CNLDATE > 0 THEN 'CNLDATE' WHEN O.CNLEMPID IS NULL AND CHK.CNLEMPID > 0 THEN 'CNLEMPID' WHEN O.ORDERSNDYN IS NULL AND CHK.ORDERSNDYN > 0 THEN 'ORDERSNDYN' WHEN O.ORDERSNDDATE IS NULL AND CHK.ORDERSNDDATE > 0 THEN 'ORDERSNDDATE' WHEN O.ORDERSNDUSERID IS NULL AND CHK.ORDERSNDUSERID > 0 THEN 'ORDERSNDUSERID' WHEN O.COHDKEY IS NULL AND CHK.COHDKEY > 0 THEN 'COHDKEY' WHEN O.EXTORDERTYPECD IS NULL AND CHK.EXTORDERTYPECD > 0 THEN 'EXTORDERTYPECD' WHEN O.ORDERERRCD IS NULL AND CHK.ORDERERRCD > 0 THEN 'ORDERERRCD' WHEN O.ORDERERRCMT IS NULL AND CHK.ORDERERRCMT > 0 THEN 'ORDERERRCMT' WHEN O.ORDERRSNCD IS NULL AND CHK.ORDERRSNCD > 0 THEN 'ORDERRSNCD' WHEN O.RECPNM IS NULL AND CHK.RECPNM > 0 THEN 'RECPNM' WHEN O.RECPADDRHD IS NULL AND CHK.RECPADDRHD > 0 THEN 'RECPADDRHD' WHEN O.RECPADDRDT IS NULL AND CHK.RECPADDRDT > 0 THEN 'RECPADDRDT' WHEN O.RECPZIPCD IS NULL AND CHK.RECPZIPCD > 0 THEN 'RECPZIPCD' WHEN O.RECPTEL01 IS NULL AND CHK.RECPTEL01 > 0 THEN 'RECPTEL01' WHEN O.RECPTEL02 IS NULL AND CHK.RECPTEL02 > 0 THEN 'RECPTEL02' WHEN O.BUYER IS NULL AND CHK.BUYER > 0 THEN 'BUYER' WHEN O.BUYERADDRHD IS NULL AND CHK.BUYERADDRHD > 0 THEN 'BUYERADDRHD' WHEN O.BUYERADDRDT IS NULL AND CHK.BUYERADDRDT > 0 THEN 'BUYERADDRDT' WHEN O.BUYERZIPCD IS NULL AND CHK.BUYERZIPCD > 0 THEN 'BUYERZIPCD' WHEN O.BUYERTEL01 IS NULL AND CHK.BUYERTEL01 > 0 THEN 'BUYERTEL01' WHEN O.BUYERTEL02 IS NULL AND CHK.BUYERTEL02 > 0 THEN 'BUYERTEL02' WHEN O.RECALLER IS NULL AND CHK.RECALLER > 0 THEN 'RECALLER' WHEN O.RECALLERADDRHD IS NULL AND CHK.RECALLERADDRHD > 0 THEN 'RECALLERADDRHD' WHEN O.RECALLERADDRDT IS NULL AND CHK.RECALLERADDRDT > 0 THEN 'RECALLERADDRDT' WHEN O.RECALLERZIPCD IS NULL AND CHK.RECALLERZIPCD > 0 THEN 'RECALLERZIPCD' WHEN O.RECALLERTEL01 IS NULL AND CHK.RECALLERTEL01 > 0 THEN 'RECALLERTEL01' WHEN 