SELECT SH.* , SW.WBLNO FROM ( SELECT ORGORDERKEY, CLAIMNO -- DLVYEXPCTDAY FROM TORDER_INTF_OBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TC ON (TI.ORGORDERKEY = TC.ORGORDERKEY OR TI.CLAIMNO = TC.CLAIMNO) --AND TI.DLVYEXPCTDAY = TC.DLVYEXPCTDAY AND TC.IFID = #{interfaceId} AND TC.OWKEY = #{owkey} JOIN TORDER_INFO_SO_HD SH ON TC.OWKEY = SH.OWKEY AND TC.COHDKEY = SH.COHDKEY LEFT JOIN TORDER_INFO_SO_WBLNO SW ON SH.OWKEY = SW.OWKEY AND SH.SOHDKEY = SW.SOHDKEY AND TC.COHDKEY = SW.COHDKEY AND SH.WKSTATUS NOT IN ( #{cancelWkstatus}, #{failWkstatus})
