) O LEFT JOIN ( SELECT OWKEY , ORDERTYPECD , SUM(CASE WHEN SOCOLUMN='SOHDKEY' THEN 1 ELSE 0 END) AS SOHDKEY , SUM(CASE WHEN SOCOLUMN='DLVYEXPCTDAY' THEN 1 ELSE 0 END) AS DLVYEXPCTDAY , SUM(CASE WHEN SOCOLUMN='ORDERISTDAY' THEN 1 ELSE 0 END) AS ORDERISTDAY , SUM(CASE WHEN SOCOLUMN='WKSTATUS' THEN 1 ELSE 0 END) AS WKSTATUS , SUM(CASE WHEN SOCOLUMN='CTKEY' THEN 1 ELSE 0 END) AS CTKEY , SUM(CASE WHEN SOCOLUMN='DLVYACKEY' THEN 1 ELSE 0 END) AS DLVYACKEY , SUM(CASE WHEN SOCOLUMN='STOREKEY' THEN 1 ELSE 0 END) AS STOREKEY , SUM(CASE WHEN SOCOLUMN='BILLKEY' THEN 1 ELSE 0 END) AS BILLKEY , SUM(CASE WHEN SOCOLUMN='PAYERKEY' THEN 1 ELSE 0 END) AS PAYERKEY , SUM(CASE WHEN SOCOLUMN='ACKEY' THEN 1 ELSE 0 END) AS ACKEY , SUM(CASE WHEN SOCOLUMN='LOGGRPCD' THEN 1 ELSE 0 END) AS LOGGRPCD , SUM(CASE WHEN SOCOLUMN='ORGORDERKEY' THEN 1 ELSE 0 END) AS ORGORDERKEY , SUM(CASE WHEN SOCOLUMN='FROMTOCTKEY' THEN 1 ELSE 0 END) AS FROMTOCTKEY , SUM(CASE WHEN SOCOLUMN='ICGRTYPE' THEN 1 ELSE 0 END) AS ICGRTYPE , SUM(CASE WHEN SOCOLUMN='ICGRKEY' THEN 1 ELSE 0 END) AS ICGRKEY , SUM(CASE WHEN SOCOLUMN='POTYPE' THEN 1 ELSE 0 END) AS POTYPE , SUM(CASE WHEN SOCOLUMN='RFRNKEY' THEN 1 ELSE 0 END) AS RFRNKEY , SUM(CASE WHEN SOCOLUMN='SALESEMPID' THEN 1 ELSE 0 END) AS SALESEMPID , SUM(CASE WHEN SOCOLUMN='DLVYEMPID' THEN 1 ELSE 0 END) AS DLVYEMPID , SUM(CASE WHEN SOCOLUMN='EDIYN' THEN 1 ELSE 0 END) AS EDIYN , SUM(CASE WHEN SOCOLUMN='CMT' THEN 1 ELSE 0 END) AS CMT , SUM(CASE WHEN SOCOLUMN='ADDCMT01' THEN 1 ELSE 0 END) AS ADDCMT01 , SUM(CASE WHEN SOCOLUMN='ADDCMT02' THEN 1 ELSE 0 END) AS ADDCMT02 , SUM(CASE WHEN SOCOLUMN='CNLYN' THEN 1 ELSE 0 END) AS CNLYN , SUM(CASE WHEN SOCOLUMN='CNLDATE' THEN 1 ELSE 0 END) AS CNLDATE , SUM(CASE WHEN SOCOLUMN='CNLEMPID' THEN 1 ELSE 0 END) AS CNLEMPID , SUM(CASE WHEN SOCOLUMN='ORDERSNDYN' THEN 1 ELSE 0 END) AS ORDERSNDYN , SUM(CASE WHEN SOCOLUMN='ORDERSNDDATE' THEN 1 ELSE 0 END) AS ORDERSNDDATE , SUM(CASE WHEN SOCOLUMN='ORDERSNDUSERID' THEN 1 ELSE 0 END) AS ORDERSNDUSERID , SUM(CASE WHEN SOCOLUMN='COHDKEY' THEN 1 ELSE 0 END) AS COHDKEY , SUM(CASE WHEN SOCOLUMN='EXTORDERTYPECD' THEN 1 ELSE 0 END) AS EXTORDERTYPECD , SUM(CASE WHEN SOCOLUMN='ORDERERRCD' THEN 1 ELSE 0 END) AS ORDERERRCD , SUM(CASE WHEN SOCOLUMN='ORDERERRCMT' THEN 1 ELSE 0 END) AS ORDERERRCMT , SUM(CASE WHEN SOCOLUMN='ORDERRSNCD' THEN 1 ELSE 0 END) AS ORDERRSNCD , SUM(CASE WHEN SOCOLUMN='RECPNM' THEN 1 ELSE 0 END) AS RECPNM , SUM(CASE WHEN SOCOLUMN='RECPADDRHD' THEN 1 ELSE 0 END) AS RECPADDRHD , SUM(CASE WHEN SOCOLUMN='RECPADDRDT' THEN 1 ELSE 0 END) AS RECPADDRDT , SUM(CASE WHEN SOCOLUMN='RECPZIPCD' THEN 1 ELSE 0 END) AS RECPZIPCD , SUM(CASE WHEN SOCOLUMN='RECPTEL01' THEN 1 ELSE 0 END) AS RECPTEL01 , SUM(CASE WHEN SOCOLUMN='RECPTEL02' THEN 1 ELSE 0 END) AS RECPTEL02 , SUM(CASE WHEN SOCOLUMN='BUYER' THEN 1 ELSE 0 END) AS BUYER , SUM(CASE WHEN SOCOLUMN='BUYERADDRHD' THEN 1 ELSE 0 END) AS BUYERADDRHD , SUM(CASE WHEN SOCOLUMN='BUYERADDRDT' THEN 1 ELSE 0 END) AS BUYERADDRDT , SUM(CASE WHEN SOCOLUMN='BUYERZIPCD' THEN 1 ELSE 0 END) AS BUYERZIPCD , SUM(CASE WHEN SOCOLUMN='BUYERTEL01' THEN 1 ELSE 0 END) AS BUYERTEL01 , SUM(CASE WHEN SOCOLUMN='BUYERTEL02' THEN 1 ELSE 0 END) AS BUYERTEL02 , SUM(CASE WHEN SOCOLUMN='RECALLER' THEN 1 ELSE 0 END) AS RECALLER , SUM(CASE WHEN SOCOLUMN='RECALLERADDRHD' THEN 1 ELSE 0 END) AS RECALLERADDRHD , SUM(CASE WHEN SOCOLUMN='RECALLERADDRDT' THEN 1 ELSE 0 END) AS RECALLERADDRDT , SUM(CASE WHEN SOCOLUMN='RECALLERZIPCD' THEN 1 ELSE 0 END) AS RECALLERZIPCD , SUM(CASE WHEN SOCOLUMN='RECALLERTEL01' THEN 1 ELSE 0 END) AS RECALLERTEL01 , SUM(CASE WHEN SOCOLUMN='RECALLERTEL02' THEN 1 ELSE 0 END) AS RECALLERTEL02 , SUM(CASE WHEN SOCOLUMN='RECALLERIYN' THEN 1 ELSE 0 END) AS RECALLERIYN , SUM(CASE WHEN SOCOLUMN='RIRSNCD' THEN 1 ELSE 0 END) AS RIRSNCD , SUM(CASE WHEN SOCOLUMN='CLAIMNO' THEN 1 ELSE 0 END) AS CLAIMNO , SUM(CASE WHEN SOCOLUMN='DLVYMETHDCD' THEN 1 ELSE 0 END) AS DLVYMETHDCD , SUM(CASE WHEN SOCOLUMN='DLVYMETHDDTCD' THEN 1 ELSE 0 END) AS DLVYMETHDDTCD , SUM(CASE WHEN SOCOLUMN='MALORDERDIV' THEN 1 ELSE 0 END) AS MALORDERDIV , SUM(CASE WHEN SOCOLUMN='NISYN' THEN 1 ELSE 0 END) AS NISYN , SUM(CASE WHEN SOCOLUMN='NISCNLRNGDIV' THEN 1 ELSE 0 END) AS NISCNLRNGDIV , SUM(CASE WHEN SOCOLUMN='PAYMTCOMPLDAY' THEN 1 ELSE 0 END) AS PAYMTCOMPLDAY , SUM(CASE WHEN SOCOLUMN='PARTERID' THEN 1 ELSE 0 END) AS PARTERID , SUM(CASE WHEN SOCOLUMN='ACCESSKEY' THEN 1 ELSE 0 END) AS ACCESSKEY , SUM(CASE WHEN SOCOLUMN='SHMISTNO' THEN 1 ELSE 0 END) AS SHMISTNO FROM TORDER_INFO_SO_CHK WHERE HDDTDIV = #{hddtdiv} AND DELYN = 'N' AND REQRDYN = 'Y' GROUP BY OWKEY, ORDERTYPECD ) CHK ON O.OWKEY = CHK.OWKEY AND O.ORDERTYPECD = CHK.ORDERTYPECD LEFT JOIN TORDER_MST_AC DC ON O.OWKEY = DC.OWKEY AND O.DLVYACKEY = DC.ACKEY LEFT JOIN TORDER_MST_AC SC ON O.OWKEY = SC.OWKEY AND O.STOREKEY = SC.ACKEY LEFT JOIN TORDER_MST_AC AC ON O.OWKEY = AC.OWKEY AND O.ACKEY = AC.ACKEY LEFT JOIN TORDER_MST_CT CT ON O.CTKEY = CT.CTKEY LEFT JOIN TORDER_MST_CT TCT ON O.FROMTOCTKEY = TCT.CTKEY LEFT JOIN ( SELECT OWKEY , ORDERTYPECD FROM TORDER_MST_ORTYPE WHERE DELYN = 'N'
AND ORDERAT=#{orderat} AND IBYN = #{ibyn} AND OBYN = #{obyn}
) OC ON O.OWKEY = OC.OWKEY AND O.ORDERTYPECD = OC.ORDERTYPECD ) T LEFT JOIN (
) EL ON T.ERRCOL = EL.SOCOLUMN LEFT JOIN TADMIN_MST_MULAAPMSG_DT ML ON EL.PARAM = ML.MULAAPMSGHDKEY AND ML.LAKEY = COALESCE(#{lakey}, 'KOR') LEFT JOIN TADMIN_MST_MULAAPMSG_DT MM ON 'MSG_' || EL.MESSAGE_CODE = MM.MULAAPMSGHDKEY AND MM.LAKEY = COALESCE(#{lakey}, 'KOR') WHERE 1=1

/* oms-socommon-sql-oracle.xml selectInValidateSoDt */ SELECT T.* , CASE WHEN T.ERRCOL IS NULL THEN 1 ELSE 0 END AS IS_SUCCESS , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.ERROR_COLUMN END AS ERROR_COLUMN , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.MESSAGE_CODE END AS ERROR_CODE , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.PARAM END AS ERROR_PARAM , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE REPLACE(REPLACE(COALESCE(MM.DISPLAYMSG, EL.SERVER_MESSAGE), #{param1}, COALESCE(ML.DISPLAYMSG, EL.PARAM)), #{param0}, COALESCE(ML.DISPLAYMSG, EL.PARAM)) END AS SERVER_MESSAGE FROM ( SELECT O.* , CASE WHEN O.OWKEY IS NULL AND CHK.OWKEY > 0 THEN 'OWKEY' WHEN O.SOHDKEY IS NULL AND CHK.SOHDKEY > 0 THEN 'SOHDKEY' WHEN O.SODTKEY IS NULL AND CHK.SODTKEY > 0 THEN 'SODTKEY' WHEN O.ICKEY IS NULL AND CHK.ICKEY > 0 THEN 'ICKEY' WHEN O.OLNICKEY IS NULL AND CHK.OLNICKEY > 0 THEN 'OLNICKEY' WHEN O.UOM IS NULL AND CHK.UOM > 0 THEN 'UOM' WHEN O.INITQTY IS NULL AND CHK.INITQTY > 0 THEN 'INITQTY' WHEN O.EXPCTQTY IS NULL AND CHK.EXPCTQTY > 0 THEN 'EXPCTQTY' WHEN O.CNFRMQTY IS NULL AND CHK.CNFRMQTY > 0 THEN 'CNFRMQTY' WHEN O.SNDQTY IS NULL AND CHK.SNDQTY > 0 THEN 'SNDQTY' WHEN O.DLVYEXPCTDAY IS NULL AND CHK.DLVYEXPCTDAY > 0 THEN 'DLVYEXPCTDAY' WHEN O.ORDERISTDAY IS NULL AND CHK.ORDERISTDAY > 0 THEN 'ORDERISTDAY' WHEN O.TTWEIGHT IS NULL AND CHK.TTWEIGHT > 0 THEN 'TTWEIGHT' WHEN O.WEIGHTUNIT IS NULL AND CHK.WEIGHTUNIT > 0 THEN 'WEIGHTUNIT' WHEN O.VOL IS NULL AND CHK.VOL > 0 THEN 'VOL' WHEN O.VOLUNIT IS NULL AND CHK.VOLUNIT > 0 THEN 'VOLUNIT' WHEN O.LOGGRPCD IS NULL AND CHK.LOGGRPCD > 0 THEN 'LOGGRPCD' WHEN O.CMT IS NULL AND CHK.CMT > 0 THEN 'CMT' WHEN O.PRDCTLOT IS NULL AND CHK.PRDCTLOT > 0 THEN 'PRDCTLOT' WHEN O.PRDCTDAY IS NULL AND CHK.PRDCTDAY > 0 THEN 'PRDCTDAY' WHEN O.WKSTATUS IS NULL AND CHK.WKSTATUS > 0 THEN 'WKSTATUS' WHEN O.RFRNCKEY IS NULL AND CHK.RFRNCKEY > 0 THEN 'RFRNCKEY' WHEN O.RFRNCDTKEY IS NULL AND CHK.RFRNCDTKEY > 0 THEN 'RFRNCDTKEY' WHEN O.ORGORDERKEY IS NULL AND CHK.ORGORDERKEY > 0 THEN 'ORGORDERKEY' WHEN O.ORGORDERDTKEY IS NULL AND CHK.ORGORDERDTKEY > 0 THEN 'ORGORDERDTKEY' WHEN O.CNFRMYN IS NULL AND CHK.CNFRMYN > 0 THEN 'CNFRMYN' WHEN O.CNLYN IS NULL AND CHK.CNLYN > 0 THEN 'CNLYN' WHEN O.NISCMT IS NULL AND CHK.NISCMT > 0 THEN 'NISCMT' WHEN O.RICMT IS NULL AND CHK.RICMT > 0 THEN 'RICMT' WHEN O.COHDKEY IS NULL AND CHK.COHDKEY > 0 THEN 'COHDKEY' WHEN O.CODTKEY IS NULL AND CHK.CODTKEY > 0 THEN 'CODTKEY' WHEN O.ORDERERRCD IS NULL AND CHK.ORDERERRCD > 0 THEN 'ORDERERRCD' WHEN O.ORDERERRCMT IS NULL AND CHK.ORDERERRCMT > 0 THEN 'ORDERERRCMT' WHEN O.ICGRKEY IS NULL AND CHK.ICGRKEY > 0 THEN 'ICGRKEY' WHEN O.ICGRTYPE IS NULL AND CHK.ICGRTYPE > 0 THEN 'ICGRTYPE' WHEN O.SPEC IS NULL AND CHK.SPEC > 0 THEN 'SPEC' WHEN O.DLVYCNTRUNIT IS NULL AND CHK.DLVYCNTRUNIT > 0 THEN 'DLVYCNTRUNIT' WHEN O.MALBOXQTY IS NULL AND CHK.MALBOXQTY > 0 THEN 'MALBOXQTY' WHEN O.MALPCSQTY IS NULL AND CHK.MALPCSQTY > 0 THEN 'MALPCSQTY' WHEN IC.ICKEY IS NULL THEN 'ICKEY_M' ELSE NULL END AS ERRCOL FROM (
SELECT SD.* , SH.CTKEY --, SH.SHMISTNO , SH.ORDERTYPECD , SW.WBLNO , SW.DLVRYCORP AS DLVRYCORPCD , TC.EXTORDERTYPECD --, SD.DLVYCNTRUNIT , ( SELECT COALESCE(MAX(RO.REQORDERUNIT), '') FROM TORDER_INFO_REQORDER RO WHERE SD.OWKEY = RO.OWKEY AND SD.RFRNCKEY = RO.REQORDERNO AND SD.ICKEY = RO.ICKEY ) AS REQORDERUNIT , ( SELECT COALESCE(MAX(RO.DLVYREQORDERUNIT), '') FROM TORDER_INFO_REQORDER RO WHERE SD.OWKEY = RO.OWKEY AND SD.RFRNCKEY = RO.REQORDERNO AND SD.ICKEY = RO.ICKEY ) AS DLVYREQORDERUNIT
, '09' AS ORGCTKEY
FROM ( SELECT REQORDERNO, CLAIMNO -- DLVYEXPCTDAY FROM TORDER_INTF_IBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TC ON (TI.REQORDERNO = TC.REQORDERNO OR TI.CLAIMNO = TC.CLAIMNO) --AND TI.DLVYEXPCTDAY = TC.DLVYEXPCTDAY AND TC.IFID = #{interfaceId} AND TC.OWKEY = #{owkey} JOIN TORDER_INFO_SO_HD SH ON TC.OWKEY = SH.OWKEY AND TC.COHDKEY = SH.COHDKEY AND SH.WKSTATUS NOT IN ( #{cancelWkstatus}, #{failWkstatus}) JOIN TORDER_INFO_SO_DT SD ON SH.OWKEY = SD.OWKEY AND SH.SOHDKEY = SD.SOHDKEY LEFT OUTER JOIN TORDER_INFO_SO_WBLNO SW ON TC.COHDKEY = SW.COHDKEY AND SD.SOHDKEY = SW.SOHDKEY AND SD.OLNICKEY = SW.ICKEY
SELECT #{item.owkey} AS OWKEY /*화주코드*/ , #{item.ordertypecd} AS ORDERTYPECD /*헤더에서 가져와야 될 주문유형*/ , #{item.sohdkey} AS SOHDKEY /*S/O번호*/ , #{item.sodtkey} AS SODTKEY /*S/O상세번호*/ , #{item.ickey} AS ICKEY /*제품코드*/ , #{item.olnickey} AS OLNICKEY , #{item.icutkey} AS ICUTKEY /*제품단위코드*/ , #{item.uom} AS UOM /*주문단위*/ , #{item.initqty} AS INITQTY /*초기수량*/ , #{item.expctqty} AS EXPCTQTY /*예정수량*/ , #{item.cnfrmqty} AS CNFRMQTY /*확정수량*/ , #{item.sndqty} AS SNDQTY /*SAP전송수량*/ , #{item.dlvyexpctday} AS DLVYEXPCTDAY /*배송예정일자*/ , #{item.orderistday} AS ORDERISTDAY /*지시일자*/ , #{item.obamt} AS OBAMT /*출고가*/ , #{item.ttweight} AS TTWEIGHT /*총중량*/ , #{item.weightunit} AS WEIGHTUNIT /*중량단위*/ , #{item.vol} AS VOL /*총부피*/ , #{item.volunit} AS VOLUNIT /*부피단위*/ , #{item.loggrpcd} AS LOGGRPCD /*상/저온 구분*/ , #{item.cmt} AS CMT /*비고*/ , #{item.prdctlot} AS PRDCTLOT /*생산 LOT*/ , #{item.prdctday} AS PRDCTDAY /*생산일자*/ , #{item.wkstatus} AS WKSTATUS /*작업(주문) 상태*/ , #{item.rfrnckey} AS RFRNCKEY /*이전참조문서번호*/ , #{item.rfrncdtkey} AS RFRNCDTKEY /*이전참조상세번호*/ , #{item.orgorderkey} AS ORGORDERKEY /*외부주문번호*/ , #{item.orgorderdtkey} AS ORGORDERDTKEY /*외부주문상세번호*/ , #{item.cnfrmyn} AS CNFRMYN /*주문취소여부*/ , #{item.cnlyn} AS CNLYN /*주문취소여부*/ , #{item.niscmt} AS NISCMT /*결품사유*/ , #{item.ricmt} AS RICMT /*반품사유*/ , #{item.cohdkey} AS COHDKEY /*CO주문번호*/ , #{item.codtkey} AS CODTKEY /*CO주문상세번호*/ , #{item.ordererrcd} AS ORDERERRCD /*주문오류 코드*/ , #{item.ordererrcmt} AS ORDERERRCMT /*주문생성 오류비고*/ , #{item.icgrkey} AS ICGRKEY /*주문생성 오류비고*/ , #{item.icgrtype} AS ICGRTYPE /*주문생성 오류비고*/ , #{item.spec} AS SPEC /*주문생성 오류비고*/ , #{item.dlvycntrunit} AS DLVYCNTRUNIT /*주문생성 오류비고*/ , #{item.malboxqty} AS MALBOXQTY /*주문생성 오류비고*/ , #{item.malpcsqty} AS MALPCSQTY /*주문생성 오류비고*/ , #{item.uploadkey} AS UPLOADKEY , #{item.uploadseq} AS UPLOADSEQ , #{item.insertdate} AS INSERTDATE /*입력 일시*/ , #{item.inserturkey} AS INSERTURKEY /*입력 사용자 ID*/ , #{item.updatedate} AS UPDATEDATE /*수정 일시*/ , #{item.updateurkey} AS UPDATEURKEY /*수정 사용자 ID*/
) O LEFT JOIN ( SELECT OWKEY , ORDERTYPECD , SUM(CASE WHEN SOCOLUMN='SOHDKEY' THEN 1 ELSE 0 END) AS SOHDKEY , SUM(CASE WHEN SOCOLUMN='SODTKEY' THEN 1 ELSE 0 END) AS SODTKEY , SUM(CASE WHEN SOCOLUMN='ICKEY' THEN 1 ELSE 0 END) AS ICKEY , SUM(CASE WHEN SOCOLUMN='OLNICKEY' THEN 1 ELSE 0 END) AS OLNICKEY , SUM(CASE WHEN SOCOLUMN='ICUTKEY' THEN 1 ELSE 0 END) AS ICUTKEY , SUM(CASE WHEN SOCOLUMN='UOM' THEN 1 ELSE 0 END) AS UOM , SUM(CASE WHEN SOCOLUMN='INITQTY' THEN 1 ELSE 0 END) AS INITQTY , SUM(CASE WHEN SOCOLUMN='EXPCTQTY' THEN 1 ELSE 0 END) AS EXPCTQTY , SUM(CASE WHEN SOCOLUMN='CNFRMQTY' THEN 1 ELSE 0 END) AS CNFRMQTY , SUM(CASE WHEN SOCOLUMN='SNDQTY' THEN 1 ELSE 0 END) AS SNDQTY , SUM(CASE WHEN SOCOLUMN='DLVYEXPCTDAY' THEN 1 ELSE 0 END) AS DLVYEXPCTDAY , SUM(CASE WHEN SOCOLUMN='ORDERISTDAY' THEN 1 ELSE 0 END) AS ORDERISTDAY , SUM(CASE WHEN SOCOLUMN='TTWEIGHT' THEN 1 ELSE 0 END) AS TTWEIGHT , SUM(CASE WHEN SOCOLUMN='WEIGHTUNIT' THEN 1 ELSE 0 END) AS WEIGHTUNIT , SUM(CASE WHEN SOCOLUMN='VOL' THEN 1 ELSE 0 END) AS VOL , SUM(CASE WHEN SOCOLUMN='VOLUNIT' THEN 1 ELSE 0 END) AS VOLUNIT , SUM(CASE WHEN SOCOLUMN='LOGGRPCD' THEN 1 ELSE 0 END) AS LOGGRPCD , SUM(CASE WHEN SOCOLUMN='CMT' THEN 1 ELSE 0 END) AS CMT , SUM(CASE WHEN SOCOLUMN='PRDCTLOT' THEN 1 ELSE 0 END) AS PRDCTLOT , SUM(CASE WHEN SOCOLUMN='PRDCTDAY' THEN 1 ELSE 0 END) AS PRDCTDAY , SUM(CASE WHEN SOCOLUMN='WKSTATUS' THEN 1 ELSE 0 END) AS WKSTATUS , SUM(CASE WHEN SOCOLUMN='RFRNCKEY' THEN 1 ELSE 0 END) AS RFRNCKEY , SUM(CASE WHEN SOCOLUMN='RFRNCDTKEY' THEN 1 ELSE 0 END) AS RFRNCDTKEY , SUM(CASE WHEN SOCOLUMN='ORGORDERKEY' THEN 1 ELSE 0 END) AS ORGORDERKEY , SUM(CASE WHEN SOCOLUMN='ORGORDERDTKEY' THEN 1 ELSE 0 END) AS ORGORDERDTKEY , SUM(CASE WHEN SOCOLUMN='CNFRMYN' THEN 1 ELSE 0 END) AS CNFRMYN , SUM(CASE WHEN SOCOLUMN='CNLYN' THEN 1 ELSE 0 END) AS CNLYN , SUM(CASE WHEN SOCOLUMN='NISCMT' THEN 1 ELSE 0 END) AS NISCMT , SUM(CASE WHEN SOCOLUMN='RICMT' THEN 1 ELSE 0 END) AS RICMT , SUM(CASE WHEN SOCOLUMN='COHDKEY' THEN 1 ELSE 0 END) AS COHDKEY , SUM(CASE WHEN SOCOLUMN='CODTKEY' THEN 1 ELSE 0 END) AS CODTKEY , SUM(CASE WHEN SOCOLUMN='ORDERERRCD' THEN 1 ELSE 0 END) AS ORDERERRCD , SUM(CASE WHEN SOCOLUMN='ORDERERRCMT' THEN 1 ELSE 0 END) AS ORDERERRCMT , SUM(CASE WHEN SOCOLUMN='ICGRKEY' THEN 1 ELSE 0 END) AS ICGRKEY , SUM(CASE WHEN SOCOLUMN='ICGRTYPE' THEN 1 ELSE 0 END) AS ICGRTYPE , SUM(CASE WHEN SOCOLUMN='SPEC' THEN 1 ELSE 0 END) AS SPEC , SUM(CASE WHEN SOCOLUMN='DLVYCNTRUNIT' THEN 1 ELSE 0 END) AS DLVYCNTRUNIT , SUM(CASE WHEN SOCOLUMN='MALBOXQTY' THEN 1 ELSE 0 END) AS MALBOXQTY , SUM(CASE WHEN SOCOLUMN='MALPCSQTY' THEN 1 ELSE 0 END) AS MALPCSQTY FROM TORDER_INFO_SO_CHK WHERE HDDTDIV = #{hddtdiv} AND DELYN = 'N' AND REQRDYN = 'Y' GROUP BY OWKEY, ORDERTYPECD ) CHK ON O.OWKEY = CHK.OWKEY AND O.ORDERTYPECD = CHK.ORDERTYPECD LEFT JOIN TORDER_MST_IC IC ON O.OWKEY = IC.OWKEY AND O.ICKEY = IC.ICKEY AND IC.DELYN = 'N' LEFT JOIN TORDER_MST_ICUTXTYPE IU ON IC.OWKEY = IU.OWKEY AND IC.ICUNITKEY = IU.ICKEY AND O.UOM = IU.ICUNITTYPE ) T LEFT JOIN (
) EL ON T.ERRCOL = EL.SOCOLUMN LEFT JOIN TADMIN_MST_MULAAPMSG_DT ML ON EL.PARAM = ML.MULAAPMSGHDKEY AND ML.LAKEY = COALESCE(#{lakey}, 'KOR') LEFT JOIN TADMIN_MST_MULAAPMSG_DT MM ON 'MSG_' || EL.MESSAGE_CODE = MM.MULAAPMSGHDKEY AND MM.LAKEY = COALESCE(#{lakey}, 'KOR') WHERE 1=1

/* oms-socommon-sql-oracle.xml selectOutValidateSoDt */ SELECT T.* , CASE WHEN T.ERRCOL IS NULL THEN 1 ELSE 0 END AS IS_SUCCESS , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.ERROR_COLUMN END AS ERROR_COLUMN , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.MESSAGE_CODE END AS ERROR_CODE , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE EL.PARAM END AS ERROR_PARAM , CASE WHEN T.ERRCOL IS NULL THEN NULL ELSE REPLACE(REPLACE(COALESCE(MM.DISPLAYMSG, EL.SERVER_MESSAGE), #{param1}, COALESCE(ML.DISPLAYMSG, EL.PARAM)), #{param0}, COALESCE(ML.DISPLAYMSG, EL.PARAM)) END AS SERVER_MESSAGE FROM ( SELECT O.* , CASE WHEN O.OWKEY IS NULL AND CHK.OWKEY > 0 THEN 'OWKEY' WHEN O.SOHDKEY IS NULL AND CHK.SOHDKEY > 0 THEN 'SOHDKEY' WHEN O.SODTKEY IS NULL AND CHK.SODTKEY > 0 THEN 'SODTKEY' WHEN O.ICKEY IS NULL AND CHK.ICKEY > 0 THEN 'ICKEY' WHEN O.OLNICKEY IS NULL AND CHK.OLNICKEY > 0 THEN 'OLNICKEY' WHEN O.UOM IS NULL AND CHK.UOM > 0 THEN 'UOM' WHEN O.INITQTY IS NULL AND CHK.INITQTY > 0 THEN 'INITQTY' WHEN O.EXPCTQTY IS NULL AND CHK.EXPCTQTY > 0 THEN 'EXPCTQTY' WHEN O.CNFRMQTY IS NULL AND CHK.CNFRMQTY > 0 THEN 'CNFRMQTY' WHEN O.SNDQTY IS NULL AND CHK.SNDQTY > 0 THEN 'SNDQTY' WHEN O.DLVYEXPCTDAY IS NULL AND CHK.DLVYEXPCTDAY > 0 THEN 'DLVYEXPCTDAY' WHEN O.ORDERISTDAY IS NULL AND CHK.ORDERISTDAY > 0 THEN 'ORDERISTDAY' WHEN O.TTWEIGHT IS NULL AND CHK.TTWEIGHT > 0 THEN 'TTWEIGHT' WHEN O.WEIGHTUNIT IS NULL AND CHK.WEIGHTUNIT > 0 THEN 'WEIGHTUNIT' WHEN O.VOL IS NULL AND CHK.VOL > 0 THEN 'VOL' WHEN O.VOLUNIT IS NULL AND CHK.VOLUNIT > 0 THEN 'VOLUNIT' WHEN O.LOGGRPCD IS NULL AND CHK.LOGGRPCD > 0 THEN 'LOGGRPCD' WHEN O.CMT IS NULL AND CHK.CMT > 0 THEN 'CMT' WHEN O.PRDCTLOT IS NULL AND CHK.PRDCTLOT > 0 THEN 'PRDCTLOT' WHEN O.PRDCTDAY IS NULL AND CHK.PRDCTDAY > 0 THEN 'PRDCTDAY' WHEN O.WKSTATUS IS NULL AND CHK.WKSTATUS > 0 THEN 'WKSTATUS' WHEN O.RFRNCKEY IS NULL AND CHK.RFRNCKEY > 0 THEN 'RFRNCKEY' WHEN O.RFRNCDTKEY IS NULL AND CHK.RFRNCDTKEY > 0 THEN 'RFRNCDTKEY' WHEN O.ORGORDERKEY IS NULL AND CHK.ORGORDERKEY > 0 THEN 'ORGORDERKEY' WHEN O.ORGORDERDTKEY IS NULL AND CHK.ORGORDERDTKEY > 0 THEN 'ORGORDERDTKEY' WHEN O.CNFRMYN IS NULL AND CHK.CNFRMYN > 0 THEN 'CNFRMYN' WHEN O.CNLYN IS NULL AND CHK.CNLYN > 0 THEN 'CNLYN' WHEN O.NISCMT IS NULL AND CHK.NISCMT > 0 THEN 'NISCMT' WHEN O.RICMT IS NULL AND CHK.RICMT > 0 THEN 'RICMT' WHEN O.COHDKEY IS NULL AND CHK.COHDKEY > 0 THEN 'COHDKEY' WHEN O.CODTKEY IS NULL AND CHK.CODTKEY > 0 THEN 'CODTKEY' WHEN O.ORDERERRCD IS NULL AND CHK.ORDERERRCD > 0 THEN 'ORDERERRCD' WHEN O.ORDERERRCMT IS NULL AND CHK.ORDERERRCMT > 0 THEN 'ORDERERRCMT' WHEN O.ICGRKEY IS NULL AND CHK.ICGRKEY > 0 THEN 'ICGRKEY' WHEN O.ICGRTYPE IS NULL AND CHK.ICGRTYPE > 0 THEN 'ICGRTYPE' WHEN O.SPEC IS NULL AND CHK.SPEC > 0 THEN 'SPEC' WHEN O.DLVYCNTRUNIT IS NULL AND CHK.DLVYCNTRUNIT > 0 THEN 'DLVYCNTRUNIT' WHEN O.MALBOXQTY IS NULL AND CHK.MALBOXQTY > 0 THEN 'MALBOXQTY' WHEN O.MALPCSQTY IS NULL AND CHK.MALPCSQTY > 0 THEN 'MALPCSQTY' WHEN IC.ICKEY IS NULL THEN 'ICKEY_M' ELSE NULL END AS ERRCOL FROM (
SELECT SD.* , SH.CTKEY , SH.ORDERTYPECD FROM ( SELECT ORGORDERKEY, CLAIMNO -- DLVYEXPCTDAY FROM TORDER_INTF_OBORDER_HD WHERE IFID = #{interfaceId} AND REQUESTDT = #{requestDt} ) TI JOIN TORDER_INFO_CO_HD TC ON (TI.ORGORDERKEY = TC.ORGORDERKEY OR TI.CLAIMNO = TC.CLAIMNO) --AND TI.DLVYEXPCTDAY = TC.DLVYEXPCTDAY AND TC.IFID = #{interfaceId} AND TC.OWKEY = #{owkey} JOIN TORDER_INFO_SO_HD SH ON TC.OWKEY = SH.OWKEY AND TC.COHDKEY = SH.COHDKEY AND SH.WKSTATUS NOT IN ( #{cancelWkstatus}, #{failWkstatus}) JOIN TORDER_INFO_SO_DT SD ON SH.OWKEY = SD.OWKEY AND SH.SOHDKEY = SD.SOHDKEY
SELECT #{item.owkey} AS OWKEY /*화주코드*/ , #{item.ordertypecd} AS ORDERTYPECD /*헤더에서 가져와야 될 주문유형*/ , #{item.sohdkey} AS SOHDKEY /*S/O번호*/ , #{item.sodtkey} AS SODTKEY /*S/O상세번호*/ , #{item.ctkey} AS CTKEY /*센터코드*/ , #{item.ickey} AS ICKEY /*제품코드*/ , #{item.olnickey} AS OLNICKEY , #{item.icutkey} AS ICUTKEY /*제품단위코드*/ , #{item.uom} AS UOM /*주문단위*/ , #{item.initqty} AS INITQTY /*초기수량*/ , #{item.expctqty} AS EXPCTQTY /*예정수량*/ , #{item.cnfrmqty} AS CNFRMQTY /*확정수량*/ , #{item.sndqty} AS SNDQTY /*SAP전송수량*/ , #{item.dlvyexpctday} AS DLVYEXPCTDAY /*배송예정일자*/ , #{item.orderistday} AS ORDERISTDAY /*지시일자*/ , #{item.obamt} AS OBAMT /*출고가*/ , #{item.ttweight} AS TTWEIGHT /*총중량*/ , #{item.weightunit} AS WEIGHTUNIT /*중량단위*/ , #{item.vol} AS VOL /*총부피*/ , #{item.volunit} AS VOLUNIT /*부피단위*/ , #{item.loggrpcd} AS LOGGRPCD /*상/저온 구분*/ , #{item.cmt} AS CMT /*비고*/ , #{item.prdctlot} AS PRDCTLOT /*생산 LOT*/ , #{item.prdctday} AS PRDCTDAY /*생산일자*/ , #{item.wkstatus} AS WKSTATUS /*작업(주문) 상태*/ , #{item.rfrnckey} AS RFRNCKEY /*이전참조문서번호*/ , #{item.rfrncdtkey} AS RFRNCDTKEY /*이전참조상세번호*/ , #{item.orgorderkey} AS ORGORDERKEY /*외부주문번호*/ , #{item.orgorderdtkey} AS ORGORDERDTKEY /*외부주문상세번호*/ , #{item.cnfrmyn} AS CNFRMYN /*주문취소여부*/ , #{item.cnlyn} AS CNLYN /*주문취소여부*/ , #{item.niscmt} AS NISCMT /*결품사유*/ , #{item.ricmt} AS RICMT /*반품사유*/ , #{item.cohdkey} AS COHDKEY /*CO주문번호*/ , #{item.codtkey} AS CODTKEY /*CO주문상세번호*/ , #{item.ordererrcd} AS ORDERERRCD /*주문오류 코드*/ , #{item.ordererrcmt} AS ORDERERRCMT /*주문생성 오류비고*/ , #{item.icgrkey} AS ICGRKEY /*주문생성 오류비고*/ , #{item.icgrtype} AS ICGRTYPE /*주문생성 오류비고*/ , #{item.spec} AS SPEC /*주문생성 오류비고*/ , #{item.dlvycntrunit} AS DLVYCNTRUNIT /*주문생성 오류비고*/ , #{item.malboxqty} AS MALBOXQTY /*주문생성 오류비고*/ , #{item.malpcsqty} AS MALPCSQTY /*주문생성 오류비고*/ , #{item.uploadkey} AS UPLOADKEY , #{item.uploadseq} AS UPLOADSEQ , #{item.insertdate} AS INSERTDATE /*입력 일시*/ , #{item.inserturkey} AS INSERTURKEY /*입력 사용자 ID*/ , #{item.updatedate} AS UPDATEDATE /*수정 일시*/ , #{item.updateurkey} AS UPDATEURKEY /*수정 사용자 ID*/
) O LEFT JOIN ( SELECT OWKEY , ORDERTYPECD , SUM(CASE WHEN SOCOLUMN='SOHDKEY' THEN 1 ELSE 0 END) AS SOHDKEY , SUM(CASE WHEN SOCOLUMN='SODTKEY' THEN 1 ELSE 0 END) AS SODTKEY , SUM(CASE WHEN SOCOLUMN='ICKEY' THEN 1 ELSE 0 END) AS ICKEY , SUM(CASE WHEN SOCOLUMN='OLNICKEY' THEN 1 ELSE 0 END) AS OLNICKEY , SUM(CASE WHEN SOCOLUMN='ICUTKEY' THEN 1 ELSE 0 END) AS ICUTKEY , SUM(CASE WHEN SOCOLUMN='UOM' THEN 1 ELSE 0 END) AS UOM , SUM(CASE WHEN SOCOLUMN='INITQTY' THEN 1 ELSE 0 END) AS INITQTY , SUM(CASE WHEN SOCOLUMN='EXPCTQTY' THEN 1 ELSE 0 END) AS EXPCTQTY , SUM(CASE WHEN SOCOLUMN='CNFRMQTY' THEN 1 ELSE 0 END) AS CNFRMQTY , SUM(CASE WHEN SOCOLUMN='SNDQTY' THEN 1 ELSE 0 END) AS SNDQTY , SUM(CASE WHEN SOCOLUMN='DLVYEXPCTDAY' THEN 1 ELSE 0 END) AS DLVYEXPCTDAY , SUM(CASE WHEN SOCOLUMN='ORDERISTDAY' THEN 1 ELSE 0 END) AS ORDERISTDAY , SUM(CASE WHEN SOCOLUMN='TTWEIGHT' THEN 1 ELSE 0 END) AS TTWEIGHT , SUM(CASE WHEN SOCOLUMN='WEIGHTUNIT' THEN 1 ELSE 0 END) AS WEIGHTUNIT , SUM(CASE WHEN SOCOLUMN='VOL' THEN 1 ELSE 0 END) AS VOL , SUM(CASE WHEN SOCOLUMN='VOLUNIT' THEN 1 ELSE 0 END) AS VOLUNIT , SUM(CASE WHEN SOCOLUMN='LOGGRPCD' THEN 1 ELSE 0 END) AS LOGGRPCD , SUM(CASE WHEN SOCOLUMN='CMT' THEN 1 ELSE 0 END) AS CMT , SUM(CASE WHEN SOCOLUMN='PRDCTLOT' THEN 1 ELSE 0 END) AS PRDCTLOT , SUM(CASE WHEN SOCOLUMN='PRDCTDAY' THEN 1 ELSE 0 END) AS PRDCTDAY , SUM(CASE WHEN SOCOLUMN='WKSTATUS' THEN 1 ELSE 0 END) AS WKSTATUS , SUM(CASE WHEN SOCOLUMN='RFRNCKEY' THEN 1 ELSE 0 END) AS RFRNCKEY , SUM(CASE WHEN SOCOLUMN='RFRNCDTKEY' THEN 1 ELSE 0 END) AS RFRNCDTKEY , SUM(CASE WHEN SOCOLUMN='ORGORDERKEY' THEN 1 ELSE 0 END) AS ORGORDERKEY , SUM(CASE WHEN SOCOLUMN='ORGORDERDTKEY' THEN 1 ELSE 0 END) AS ORGORDERDTKEY , SUM(CASE WHEN SOCOLUMN='CNFRMYN' THEN 1 ELSE 0 END) AS CNFRMYN , SUM(CASE WHEN SOCOLUMN='CNLYN' THEN 1 ELSE 0 END) AS CNLYN , SUM(CASE WHEN SOCOLUMN='NISCMT' THEN 1 ELSE 0 END) AS NISCMT , SUM(CASE WHEN SOCOLUMN='RICMT' THEN 1 ELSE 0 END) AS RICMT , SUM(CASE WHEN SOCOLUMN='COHDKEY' THEN 1 ELSE 0 END) AS COHDKEY , SUM(CASE WHEN SOCOLUMN='CODTKEY' THEN 1 ELSE 0 END) AS CODTKEY , SUM(CASE WHEN SOCOLUMN='ORDERERRCD' THEN 1 ELSE 0 END) AS ORDERERRCD , SUM(CASE WHEN SOCOLUMN='ORDERERRCMT' THEN 1 ELSE 0 END) AS ORDERERRCMT , SUM(CASE WHEN SOCOLUMN='ICGRKEY' THEN 1 ELSE 0 END) AS ICGRKEY , SUM(CASE WHEN SOCOLUMN='ICGRTYPE' THEN 1 ELSE 0 END) AS ICGRTYPE , SUM(CASE WHEN SOCOLUMN='SPEC' THEN 1 ELSE 0 END) AS SPEC , SUM(CASE WHEN SOCOLUMN='DLVYCNTRUNIT' THEN 1 ELSE 0 END) AS DLVYCNTRUNIT , SUM(CASE WHEN SOCOLUMN='MALBOXQTY' THEN 1 ELSE 0 END) AS MALBOXQTY , SUM(CASE WHEN SOCOLUMN='MALPCSQTY' THEN 1 ELSE 0 END) AS MALPCSQTY FROM TORDER_INFO_SO_CHK WHERE HDDTDIV = #{hddtdiv} AND DELYN = 'N' AND REQRDYN = 'Y' GROUP BY OWKEY, ORDERTYPECD ) CHK ON O.OWKEY = CHK.OWKEY AND O.ORDERTYPECD = CHK.ORDERTYPECD LEFT JOIN TORDER_MST_IC IC ON O.OWKEY = IC.OWKEY AND O.ICKEY = IC.ICKEY AND IC.DELYN = 'N' LEFT JOIN TORDER_MST_ICUTXTYPE IU ON IC.OWKEY = IU.OWKEY AND IC.ICUNITKEY = IU.ICKEY AND O.UOM = IU.ICUNITTYPE ) T LEFT JOIN (
) EL ON T.ERRCOL = EL.SOCOLUMN LEFT JOIN TADMIN_MST_MULAAPMSG_DT ML ON EL.PARAM = ML.MULAAPMSGHDKEY AND ML.LAKEY = COALESCE(#{lakey}, 'KOR') LEFT JOIN TADMIN_MST_MULAAPMSG_DT MM ON 'MSG_' || EL.MESSAGE_CODE = MM.MULAAPMSGHDKEY AND MM.LAKEY = COALESCE(#{lakey}, 'KOR') WHERE 1=1

