/* oms-socommon-sql-oracle.xml updateValidateUploadSo */ UPDATE TORDER_UPLOAD_SO H SET (ORDERERRCD , ORDERERRCMT , UPDATEDATE , UPDATEURKEY ) = ( SELECT T.ORDERERRCD /*주문오류 코드*/ , T.ORDERERRCMT /*주문생성 오류비고*/ , #{interfaceDate} AS UPDATEDATE /*수정 일시*/ , #{interfaceUrkey} AS UPDATEURKEY /*수정 사용자 ID*/ FROM (
SELECT #{item.uploadkey} AS UPLOADKEY , #{item.ackey} AS ACKEY /*공급처*/ , #{item.dlvyackey} AS DLVYACKEY /*배송처*/ , #{item.storekey} AS STOREKEY /*판매처*/ , #{item.fromtoctkey} AS FROMTOCTKEY , #{item.ctkey} AS CTKEY /*센터코드*/ , #{item.dlvyexpctday} AS DLVYEXPCTDAY /*예정일자*/ , #{item.orderistday} AS ORDERISTDAY /*지시일자*/ , #{item.ordertypecd} AS ORDERTYPECD /*주문유형*/ , #{item.cmt} AS CMT /*헤더기준 비고*/ , #{item.ordererrcd} AS ORDERERRCD /*주문오류 코드*/ , #{item.serverMessage} AS ORDERERRCMT /*주문생성 오류비고*/
) T WHERE T.UPLOADKEY = H.UPLOADKEY AND COALESCE(T.ACKEY, 'X') = COALESCE(H.ACKEY, 'X') AND COALESCE(T.DLVYACKEY, 'X') = COALESCE(H.DLVYACKEY, 'X') AND COALESCE(T.STOREKEY, 'X') = COALESCE(H.STOREKEY, 'X') AND COALESCE(T.FROMTOCTKEY, 'X') = COALESCE(H.FROMTOCTKEY, 'X') AND COALESCE(T.CTKEY, 'X') = COALESCE(H.CTKEY, 'X') AND COALESCE(T.DLVYEXPCTDAY, 'X') = COALESCE(H.DLVYEXPCTDAY, 'X') AND COALESCE(T.ORDERISTDAY, 'X') = COALESCE(H.ORDERISTDAY, 'X') AND COALESCE(T.ORDERTYPECD, 'X') = COALESCE(H.ORDERTYPECD, 'X') AND COALESCE(T.CMT, 'X') = COALESCE(H.CMT, 'X') ) WHERE EXISTS ( SELECT 1 FROM (
SELECT #{item.uploadkey} AS UPLOADKEY , #{item.ackey} AS ACKEY /*공급처*/ , #{item.dlvyackey} AS DLVYACKEY /*배송처*/ , #{item.storekey} AS STOREKEY /*판매처*/ , #{item.fromtoctkey} AS FROMTOCTKEY , #{item.ctkey} AS CTKEY /*센터코드*/ , #{item.dlvyexpctday} AS DLVYEXPCTDAY /*예정일자*/ , #{item.orderistday} AS ORDERISTDAY /*지시일자*/ , #{item.ordertypecd} AS ORDERTYPECD /*주문유형*/ , #{item.cmt} AS CMT /*헤더기준 비고*/
) INTF WHERE INTF.UPLOADKEY = H.UPLOADKEY AND COALESCE(INTF.ACKEY, 'X') = COALESCE(H.ACKEY, 'X') AND COALESCE(INTF.DLVYACKEY, 'X') = COALESCE(H.DLVYACKEY, 'X') AND COALESCE(INTF.STOREKEY, 'X') = COALESCE(H.STOREKEY, 'X') AND COALESCE(INTF.FROMTOCTKEY, 'X') = COALESCE(H.FROMTOCTKEY, 'X') AND COALESCE(INTF.CTKEY, 'X') = COALESCE(H.CTKEY, 'X') AND COALESCE(INTF.DLVYEXPCTDAY, 'X') = COALESCE(H.DLVYEXPCTDAY, 'X') AND COALESCE(INTF.ORDERISTDAY, 'X') = COALESCE(H.ORDERISTDAY, 'X') AND COALESCE(INTF.ORDERTYPECD, 'X') = COALESCE(H.ORDERTYPECD, 'X') AND COALESCE(INTF.CMT, 'X') = COALESCE(H.CMT, 'X') )

/* oms-socommon-sql-oracle.xml updateValidateUploadSoItem */ UPDATE TORDER_UPLOAD_SO H SET (ORDERERRCD , ORDERERRCMT , UPDATEDATE , UPDATEURKEY ) = ( SELECT T.ORDERERRCD /*주문오류 코드*/ , T.ORDERERRCMT /*주문생성 오류비고*/ , #{interfaceDate} AS UPDATEDATE /*수정 일시*/ , #{interfaceUrkey} AS UPDATEURKEY /*수정 사용자 ID*/ FROM (
