) INTF WHERE INTF.UPLOADKEY = H.UPLOADKEY AND INTF.UPLOADSEQ = H.UPLOADSEQ )

/* oms-socommon-sql-oracle.xml updateValidateUpload */ UPDATE TORDER_UPLOAD_SO H SET (ORDERERRCD , ORDERERRCMT , UPDATEDATE , UPDATEURKEY ) = ( SELECT T.ORDERERRCD /*주문오류 코드*/ , T.ORDERERRCMT /*주문생성 오류비고*/ , #{interfaceDate} AS UPDATEDATE /*수정 일시*/ , #{interfaceUrkey} AS UPDATEURKEY /*수정 사용자 ID*/ FROM (
SELECT #{item.uploadkey} AS UPLOADKEY , #{item.uploadseq} AS UPLOADSEQ , #{item.ordererrcd} AS ORDERERRCD /*주문오류 코드*/ , #{item.ordererrcmt} AS ORDERERRCMT /*주문생성 오류비고*/
) T WHERE T.UPLOADKEY = H.UPLOADKEY AND T.UPLOADSEQ = H.UPLOADSEQ ) WHERE EXISTS ( SELECT 1 FROM (
