) T WHERE T.OWKEY = M.OWKEY AND T.SOHDKEY = M.SOHDKEY AND T.SODTKEY = M.SODTKEY )

/* oms-socommon-sql-oracle.xml updateValidateErrSo */ UPDATE TORDER_INFO_SO_HD M SET (WKSTATUS , ORDERERRCD , ORDERERRCMT , UPDATEDATE , UPDATEURKEY ) = ( SELECT #{errWkstatus} AS WKSTATUS , T.ORDERERRCD /*주문오류 코드*/ , T.ORDERERRCMT /*주문생성 오류비고*/ , #{interfaceDate} AS UPDATEDATE /*수정 일시*/ , #{interfaceUrkey} AS UPDATEURKEY /*수정 사용자 ID*/ FROM (
SELECT #{item.owkey} AS OWKEY , #{item.sohdkey} AS SOHDKEY , #{item.errorCode} AS ORDERERRCD /*주문오류 코드*/ , #{item.serverMessage} AS ORDERERRCMT /*주문생성 오류비고*/
) T WHERE T.OWKEY = M.OWKEY AND T.SOHDKEY = M.SOHDKEY ) WHERE EXISTS ( SELECT 1 FROM (
