/* oms-socommon-sql-oracle.xml insetInboundEODtWms */ INSERT INTO TWORK_INFO_IB_DT ( OWKEY , CTKEY , ICKEY , ICUTKEY , INITQTY , EXQTY , CFQTY , UOM , SALEPRICE , PRODUCTDATE , ATTRIBUTE1 /* 재고속성1(TC/DC) */ , ATTRIBUTE2 /* 재고속성2(일반/보세) */ , PRODUCTLOT , IBHDKEY , ORHDKEY , WKSTATUS , IBDTKEY , ORDTKEY , EXTERNORDERKEY , EXTERNORDERLINENUM , ICGRKEY , ICGRTYPE , LOGGRPCD , ACKEY , INSERTDATE , INSERTURKEY , UPDATEDATE , UPDATEURKEY , UPDATEKEY ) SELECT X.OWKEY , X.CTKEY , X.ICKEY , X.ICUTKEY , X.INITQTY , X.EXQTY , X.CFQTY , X.UOM , X.SALEPRICE , CASE WHEN X.PRODUCT_DT IS NOT NULL THEN X.PRODUCT_DT || '000000' ELSE NULL END AS PRODUCT_DT /* 유효일자는 입고확인 후 */ , '2' AS DC , '1' , X.PRODUCT_LOT , HD.IBHDKEY , X.SOHDKEY , X.WKSTATUS , X.SODTKEY , X.SODTKEY , X.EXTERNORDERKEY , X.EXTERNORDERDETAILKEY , X.ICGRKEY , X.ICGRTYPE , X.LOGGRPCD , X.ACKEY , #{interfaceDate} , X.INSERTURKEY , #{interfaceDate} , X.UPDATEURKEY , #{interfaceDate}
FROM (
) X INNER JOIN TWORK_INFO_IB_HD HD ON HD.ORHDKEY = X.SOHDKEY

/* oms-socommon-sql-oracle.xml insertEOTms */ INSERT INTO TT_SHPM_T ( SHPMID /*주문아이디*/ , SHPMNO /*주문번호*/ , SHPMTRCNO /*주문트래킹번호*/ , CUROPTLSTTID /*상태*/ , DRTSHPYN /*직송여부*/ , FRMPICKUPDATE /*출발*/ , TOPICKUPDATE /*출발*/ , FRMDELIVERYDATE /*도착*/ , TODELIVERYDATE /*도착*/ , DCLVAL /*신고가격*/ , VOL /*부피*/ , WGT /*무게*/ , QTY /*수량*/ , UGTY /*긴급*/ , HDTY /*보류*/ , DIVCD /*구분*/ , CTKEY , LOGGRPCD /*물류그룹코드*/ , PLANID /*계획 ID*/ , OWKEY , BILLTOCUSTCD /*청구고객코드*/ , FRMSHIPLOCTYPCD /*출발지타입*/ , DFTORISHPGLOCCD /*출발지코드*/ , FRMSHPGLOCNM /*출발지명*/ , FRMSHPGADDRID /*출발지주소아이디*/ , FRMCTYNM /*출발지도시코드*/ , FRMZIPCD /*출발지우편번호*/ , TOSHIPLOCTYPCD /*도착지타입*/ , DFTDESTSHPGLOCCD /*도착지코드*/ , TOSHPGLOCNM /*도착지명*/ , TOSHPGADDRID /*도착지주소아이디*/ , TOCTYNM /*도착지 도시코드*/ , TOZIPCD /*도착지 우편번호코드*/ , OBHDTYPE , ATTRIBUTE1 /*추가속성정의1*/ , ATTRIBUTE2 /*추가속성정의2*/ , ATTRIBUTE5 /*추가속성정의5(납품예정일)*/ , DELYN /*삭제여부*/ , OR_HD_DT , INSERTDATE /*생성일자*/ , UPDATEDATE /*수정일자*/ , INSERTURKEY , UPDATEURKEY ) SELECT nextval('seq_tt_shpm_t') AS SHPMID , X.SOHDKEY , X.EXTERNORDERKEY ,'105' AS SHPMTRCNO ,'Y' AS DRTSHPYN , X.OR_HDDATE || '000000' AS FRMPICKUPDATE , X.OR_HDDATE || '000000' AS TOPICKUPDATE , X.OR_HDDATE || '000000' AS FRMDELIVERYDATE , X.OR_HDDATE || '000000' AS TODELIVERYDATE , X.TOT_INDIAMT , X.TOTALVOLUME , X.TOTALWEIGHT , X.TOT_CONVERTQTY , 'N' /*긴급*/ , 'N' /*보류*/ , X.CTKEY , X.CTKEY , X.LOGGRPCD , X.PLANID , X.OWKEY , X.OWKEY /*출발지정보*/ , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.TO_CTKEY IS NOT NULL THEN '3' /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN '2' /*배송처*/ WHEN X.ACKEY IS NOT NULL THEN '1' /*납품처*/ ELSE NULL END ELSE '3' END FRMSHIPLOCTYPCD , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.TO_CTKEY IS NOT NULL THEN X.TO_CTKEY /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN X.DELIVERY_KEY /*배송처*/ WHEN X.ACKEY IS NOT NULL THEN X.ACKEY /*납품처*/ ELSE NULL END ELSE X.CTKEY END DFTORISHPGLOCCD , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.TO_CTKEY IS NOT NULL THEN FRCT.CTNM /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN S.STORENM /*배송처*/ WHEN X.ACKEY IS NOT NULL THEN AC.ACNM /*납품처*/ ELSE NULL END ELSE CT.CTNM END FRMSHPGLOCNM , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.TO_CTKEY IS NOT NULL THEN FRCT.ADDRID /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN S.ADDRID /*배송처*/ WHEN X.ACKEY IS NOT NULL THEN AC.ADDRID /*납품처*/ ELSE NULL END ELSE CT.ADDRID END FRMSHPGADDRID , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.TO_CTKEY IS NOT NULL THEN FRCT.ADDR1||FRCT.ADDR2 /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN S.ADDR1||S.ADDR2 /*배송처*/ WHEN X.ACKEY IS NOT NULL THEN AC.ADDR1||AC.ADDR2 /*납품처*/ ELSE NULL END ELSE CT.ADDR1||CT.ADDR2 END FRMCTYNM
, CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.TO_CTKEY IS NOT NULL THEN FRCT.ZIPCD /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN S.ZIPCD /*배송처*/ WHEN X.ACKEY IS NOT NULL THEN AC.ZIPCD /*납품처*/ ELSE NULL END ELSE CT.ZIPCD END FRMCTYNM /*도착지정보*/ , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.CTKEY IS NOT NULL THEN '3' /*센터*/ ELSE NULL END ELSE CASE WHEN X.TO_CTKEY IS NOT NULL THEN '3' /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN '2' /*배송처*/ WHEN X.ACKEY IS NOT NULL THEN '1' /*납품처*/ ELSE NULL END END TOSHIPLOCTYPCD , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.CTKEY IS NOT NULL THEN X.CTKEY /*센터*/ ELSE NULL END ELSE CASE WHEN X.TO_CTKEY IS NOT NULL THEN X.TO_CTKEY /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN X.DELIVERY_KEY /*배송처*/ ELSE NULL END END DFTDESTSHPGLOCCD , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.CTKEY IS NOT NULL THEN CT.CTNM /*센터*/ ELSE NULL END ELSE CASE WHEN X.TO_CTKEY IS NOT NULL THEN FRCT.CTNM /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN S.STORENM /*배송처*/ ELSE NULL END END TOSHPGLOCNM , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.CTKEY IS NOT NULL THEN CT.ADDRID /*센터*/ ELSE NULL END ELSE CASE WHEN X.TO_CTKEY IS NOT NULL THEN FRCT.ADDRID /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN S.ADDRID /*배송처*/ ELSE NULL END END TOSHPGADDRID
, CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.CTKEY IS NOT NULL THEN CT.ADDR1||CT.ADDR2 /*센터*/ ELSE NULL END ELSE CASE WHEN X.TO_CTKEY IS NOT NULL THEN FRCT.ADDR1||FRCT.ADDR2 /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN S.ADDR1||S.ADDR2 /*배송처*/ ELSE NULL END END TOCTYNM
, CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.CTKEY IS NOT NULL THEN CT.ZIPCD /*센터*/ ELSE NULL END ELSE CASE WHEN X.TO_CTKEY IS NOT NULL THEN FRCT.ZIPCD /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN S.ZIPCD /*배송처*/ ELSE NULL END END TOZIPCD , X.OBHDTYPE , X.TMSOBHDTYPE , '1' /*배수수량 */ , X.OR_HDDATE , 'N' AS DELYN , X.OR_HDDATE , #{interfaceDate} , #{interfaceDate} , X.INSERTURKEY , X.UPDATEURKEY FROM (
) X LEFT OUTER JOIN TADMIN_MST_STORE S ON S.OWKEY = X.OWKEY AND X.DELIVERY_KEY = S.STOREKEY LEFT OUTER JOIN TADMIN_MST_AC AC ON AC.OWKEY = X.OWKEY AND X.DELIVERY_KEY = AC.ACKEY LEFT OUTER JOIN TADMIN_MST_CT FRCT ON X.TO_CTKEY = FRCT.CTKEY INNER JOIN TADMIN_MST_CT CT ON X.CTKEY = CT.CTKEY WHERE X.TMSYN ='Y'

/* oms-socommon-sql-oracle.xml insertEOTmsLeg */ INSERT INTO TT_SHPM_LEG_T ( SHPMLEGID , SHPMID , SHPMNO , SHPMTRCNO , CUROPTLSTTID , DRTSHPYN , FRMPICKUPDATE , TOPICKUPDATE , FRMDELIVERYDATE , TODELIVERYDATE , DCLVAL , VOL , WGT , QTY , ORDRQTY , ORDRWGT , ORDRVOL , RCVDVOL , RCVDQTY , RCVDWGT , UGTY , HDTY , DIVCD , CTKEY , LOGGRPCD , PLANID , BILLTOCUSTCD , OWKEY , FRMSHIPLOCTYPCD , DFTORISHPGLOCCD , FRMSHPGLOCNM , FRMSHPGADDRID , FRMCTYNM , FRMZIPCD , TOSHIPLOCTYPCD , DFTDESTSHPGLOCCD , TOSHPGLOCNM , TOSHPGADDRID , TOCTYNM , TOZIPCD , DELYN , OR_HD_DT , OBHDTYPE , INSERTDATE , UPDATEDATE , INSERTURKEY , UPDATEURKEY )
SELECT nextval('seq_tt_shpm_leg_t') ,Z.SHPMID ,X.SOHDKEY ,X.EXTERNORDERKEY ,'200' ,'Y' ,X.OR_HDDATE || '000000' ,X.OR_HDDATE || '000000' ,X.OR_HDDATE || '000000' ,X.OR_HDDATE || '000000' ,X.TOT_INDIAMT ,X.TOTALVOLUME ,X.TOTALWEIGHT ,X.TOT_CONVERTQTY ,X.TOT_CONVERTQTY ,X.TOTALWEIGHT ,X.TOTALVOLUME ,0 RCVDVOL ,0 RCVDQTY ,0 RCVDWGT , 'N' /*긴급*/ , 'N' /*보류*/ ,X.CTKEY AS DIVCD ,X.CTKEY ,X.LOGGRPCD ,X.PLANID ,X.OWKEY ,X.OWKEY /* 출발지 정보 */ , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.TO_CTKEY IS NOT NULL THEN '3' /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN '2' /*배송처*/ WHEN X.ACKEY IS NOT NULL THEN '1' /*납품처*/ ELSE NULL END ELSE '3' END FRMSHIPLOCTYPCD , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.TO_CTKEY IS NOT NULL THEN X.TO_CTKEY /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN X.DELIVERY_KEY /*배송처*/ WHEN X.ACKEY IS NOT NULL THEN X.ACKEY /*납품처*/ ELSE NULL END ELSE X.CTKEY END DFTORISHPGLOCCD , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.TO_CTKEY IS NOT NULL THEN FRCT.CTNM /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN S.STORENM /*배송처*/ WHEN X.ACKEY IS NOT NULL THEN AC.ACNM /*납품처*/ ELSE NULL END ELSE CT.CTNM END FRMSHPGLOCNM , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.TO_CTKEY IS NOT NULL THEN FRCT.ADDRID /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN S.ADDRID /*배송처*/ WHEN X.ACKEY IS NOT NULL THEN AC.ADDRID /*납품처*/ ELSE NULL END ELSE CT.ADDRID END FRMSHPGADDRID , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.TO_CTKEY IS NOT NULL THEN FRCT.ADDR1||FRCT.ADDR2 /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN S.ADDR1||S.ADDR2 /*배송처*/ WHEN X.ACKEY IS NOT NULL THEN AC.ADDR1||AC.ADDR2 /*납품처*/ ELSE NULL END ELSE CT.ADDR1||CT.ADDR2 END FRMCTYNM
, CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.TO_CTKEY IS NOT NULL THEN FRCT.ZIPCD /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN S.ZIPCD /*배송처*/ WHEN X.ACKEY IS NOT NULL THEN AC.ZIPCD /*납품처*/ ELSE NULL END ELSE CT.ZIPCD END FRMCTYNM /*도착지정보*/ , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.CTKEY IS NOT NULL THEN '3' /*센터*/ ELSE NULL END ELSE CASE WHEN X.TO_CTKEY IS NOT NULL THEN '3' /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN '2' /*배송처*/ WHEN X.ACKEY IS NOT NULL THEN '1' /*납품처*/ ELSE NULL END END TOSHIPLOCTYPCD , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.CTKEY IS NOT NULL THEN X.CTKEY /*센터*/ ELSE NULL END ELSE CASE WHEN X.TO_CTKEY IS NOT NULL THEN X.TO_CTKEY /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN X.DELIVERY_KEY /*배송처*/ ELSE NULL END END DFTDESTSHPGLOCCD , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.CTKEY IS NOT NULL THEN CT.CTNM /*센터*/ ELSE NULL END ELSE CASE WHEN X.TO_CTKEY IS NOT NULL THEN FRCT.CTNM /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN S.STORENM /*배송처*/ ELSE NULL END END TOSHPGLOCNM , CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.CTKEY IS NOT NULL THEN CT.ADDRID /*센터*/ ELSE NULL END ELSE CASE WHEN X.TO_CTKEY IS NOT NULL THEN FRCT.ADDRID /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN S.ADDRID /*배송처*/ ELSE NULL END END TOSHPGLOCNM
, CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.CTKEY IS NOT NULL THEN CT.ADDR1||CT.ADDR2 /*센터*/ ELSE NULL END ELSE CASE WHEN X.TO_CTKEY IS NOT NULL THEN FRCT.ADDR1||FRCT.ADDR2 /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN S.ADDR1||S.ADDR2 /*배송처*/ ELSE NULL END END TOCTYNM
, CASE WHEN X.IBYN ='Y' THEN CASE WHEN X.CTKEY IS NOT NULL THEN CT.ZIPCD /*센터*/ ELSE NULL END ELSE CASE WHEN X.TO_CTKEY IS NOT NULL THEN FRCT.ZIPCD /*센터*/ WHEN X.DELIVERY_KEY IS NOT NULL THEN S.ZIPCD /*배송처*/ ELSE NULL END END TOZIPCD , 'N' AS DELYN , X.OR_HDDATE , X.OBHDTYPE , #{interfaceDate} , #{interfaceDate} , X.INSERTURKEY , X.UPDATEURKEY FROM (
) X LEFT OUTER JOIN TADMIN_MST_STORE S ON S.OWKEY = X.OWKEY AND X.DELIVERY_KEY = S.STOREKEY LEFT OUTER JOIN TADMIN_MST_AC AC ON AC.OWKEY = X.OWKEY AND X.DELIVERY_KEY = AC.ACKEY LEFT OUTER JOIN TADMIN_MST_CT FRCT ON X.TO_CTKEY = FRCT.CTKEY INNER JOIN TADMIN_MST_CT CT ON X.CTKEY = CT.CTKEY INNER JOIN TT_SHPM_T Z ON Z.SHPMNO = X.SOHDKEY WHERE X.TMSYN ='Y'

/* oms-socommon-sql-oracle.xml insertEODtTms */ INSERT INTO TT_SHPM_DETL_T ( SHPMDETLID , SHPMNO , ITEMCD , SHPMID , LEN , WDTH , HGHT , QTY , WGT , VOL , ORDRQTY , ICUTQTY , ORDRWGT , ORDRVOL , DCLVAL , ATTRIBUTE1 , ATTRIBUTE2 , ATTRIBUTE3 , ATTRIBUTE4 , ATTRIBUTE6 /*DCLVAL */ , ATTRIBUTE8 /*UOM*/ , DELYN , INSERTDATE , UPDATEDATE , INSERTURKEY , UPDATEURKEY )
SELECT nextval('seq_tt_shpm_detl_t') AS SHPMDETLID ,X.SOHDKEY ,X.ICKEY ,Z.SHPMID ,CASE WHEN Y.SIZEUNIT ='MM' THEN COALESCE(MU.LENGTH, COALESCE(Y.LENGTH, 0)) WHEN Y.SIZEUNIT ='CM' THEN COALESCE(MU.LENGTH, COALESCE(Y.LENGTH, 0)) * 1000 WHEN Y.SIZEUNIT ='M' THEN COALESCE(MU.LENGTH, COALESCE(Y.LENGTH, 0)) * 1000000 ELSE COALESCE(MU.LENGTH, Y.LENGTH) END AS LENGTH ,CASE WHEN Y.SIZEUNIT ='MM' THEN COALESCE(MU.WIDTH, COALESCE(Y.WIDTH, 0)) WHEN Y.SIZEUNIT ='CM' THEN COALESCE(MU.WIDTH, COALESCE(Y.WIDTH, 0)) * 1000 WHEN Y.SIZEUNIT ='M' THEN COALESCE(MU.WIDTH, COALESCE(Y.WIDTH, 0)) * 1000000 ELSE COALESCE(MU.WIDTH, Y.WIDTH) END AS WIDTH ,CASE WHEN Y.SIZEUNIT ='MM' THEN COALESCE(MU.HEIGHT, COALESCE(Y.HEIGHT, 0)) WHEN Y.SIZEUNIT ='CM' THEN COALESCE(MU.HEIGHT, COALESCE(Y.HEIGHT, 0)) * 1000 WHEN Y.SIZEUNIT ='M' THEN COALESCE(MU.HEIGHT, COALESCE(Y.HEIGHT, 0)) * 1000000 ELSE COALESCE(MU.HEIGHT, Y.HEIGHT) END AS HEIGHT ,X.EXQTY , CASE WHEN Y.WEIGHTUNIT ='G' THEN COALESCE(MU.WEIGHT, COALESCE(Y.WEIGHT, 0)) WHEN Y.WEIGHTUNIT ='KG' THEN COALESCE(MU.WEIGHT, COALESCE(Y.WEIGHT, 0)) * 1000 WHEN Y.WEIGHTUNIT ='MT' THEN COALESCE(MU.WEIGHT, COALESCE(Y.WEIGHT, 0)) * 1000000 ELSE COALESCE(MU.WEIGHT, COALESCE(Y.WEIGHT, 0)) END AS WGT ,X.VOLUME AS VOL ,X.EXQTY AS ORDRQTY ,Y.ICUNITQTY ,X.TOTALWEIGHT AS ORDRWGT ,X.VOLUME AS ORDRVOL ,X.INDIAMT ,'1' AS ATTRIBUTE1 ,X.SODTKEY ,X.EXTERNORDERKEY ,X.EXTERNORDERDETAILKEY ,X.OB_COSTPRICE AS ATTRIBUTE6 ,X.UOM ,'N' ,#{interfaceDate} ,#{interfaceDate} ,X.INSERTURKEY ,X.UPDATEURKEY FROM (
) X INNER JOIN TT_SHPM_T Z ON Z.SHPMNO = X.SOHDKEY INNER JOIN TADMIN_MST_ICUTXTYPE Y ON Y.OWKEY = X.OWKEY AND Y.ICUNITKEY = X.ICUTKEY AND Y.ICUNITTYPE = X.UOM LEFT JOIN TADMIN_MST_ICMEASUREMENT MU ON X.OWKEY = MU.OWKEY AND X.ICUTKEY = MU.ICUNITKEY AND X.UOM = MU.ICUNITTYPE AND Z.CTKEY = MU.CTKEY

mapper.update:
		   /* oms-socommon-sql-oracle.xml updateSODT */
		UPDATE TORDER_INFO_SO_DT SD SET  WKSTATUS = #{sendSoStatus}
										,UPDATEDATE = #{interfaceDate}
										,UPDATEURKEY = #{userid}
	    WHERE EXISTS ( 
					     SELECT 1
					     FROM  
					      (

					        SELECT #{item.sohdkey} AS SOHDKEY 

					       ) VHD  WHERE  SD.SOHDKEY = VHD.SOHDKEY
					      ) 
           /*통제처리여부*/

		/* oms-socommon-sql-oracle.xml updateSOHD */
		UPDATE TORDER_INFO_SO_HD SH SET  ORDERSNDYN = 'Y'
										,ORDERSNDDATE = #{interfaceDate}
										,ORDERSNDUSERID = #{userid}
										,WKSTATUS = #{sendSoStatus} 
										,UPDATEDATE = #{interfaceDate}
										,UPDATEURKEY = #{userid}
	    WHERE EXISTS ( 
					     SELECT 1
					     FROM  
					      (

					        SELECT #{item.sohdkey} AS SOHDKEY 

					       ) VHD  WHERE  SH.SOHDKEY = VHD.SOHDKEY
					      ) 
           /*통제처리여부*/

	   /* oms-socommon-sql-oracle.xml updateCODT */
	UPDATE TORDER_INFO_CO_DT CD SET  WKSTATUS = #{sendCoStatus}
									,UPDATEDATE = #{interfaceDate}
									,UPDATEURKEY = #{userid}
    WHERE EXISTS ( 
				     SELECT 1
				     FROM  
				      (

				        SELECT #{item.sohdkey} AS SOHDKEY

				       ) VHD 
				     JOIN TORDER_INFO_SO_DT SD
				       ON VHD.SOHDKEY = SD.SOHDKEY
				      AND SD.OWKEY = #{owkey} 
				    WHERE 1 = 1
				       /*통제처리여부*/
				      AND SD.COHDKEY = CD.COHDKEY
				      AND SD.CODTKEY = CD.CODTKEY
				      AND SD.OWKEY = CD.OWKEY	
				 )

	   /* oms-socommon-sql-oracle.xml updateCOHD */
	UPDATE TORDER_INFO_CO_HD HD SET  WKSTATUS = #{sendCoStatus} 
									,UPDATEDATE = #{interfaceDate}
									,UPDATEURKEY = #{userid}
    WHERE EXISTS ( 
				     SELECT 1
				     FROM (
				     		SELECT SH.OWKEY
						         , SH.COHDKEY
						      FROM (

							        SELECT #{item.sohdkey} AS SOHDKEY

							       ) VHD 
						      JOIN TORDER_INFO_SO_HD SH
						        ON VHD.SOHDKEY = SH.SOHDKEY
						       AND SH.OWKEY = #{owkey} 
						     WHERE 1 = 1 
						      /*통제처리여부*/
				          ) TT
				     WHERE TT.COHDKEY = HD.COHDKEY
					   AND TT.OWKEY = HD.OWKEY  

				)

	/* oms-socommon-sql-oracle.xml updateSODTControl */
	UPDATE TORDER_INFO_SO_DT M
	   SET WKSTATUS = #{sowksts}
	     , UPDATEDATE = #{interfaceDate}
	     , UPDATEURKEY = #{userid}
     WHERE EXISTS ( 
					SELECT 1
			          FROM (

					        SELECT #{item.sohdkey} AS SOHDKEY 

			               ) VHD
			          JOIN TORDER_INFO_SO_DT SD
			            ON VHD.SOHDKEY = SD.SOHDKEY
			           AND SD.OWKEY = #{owkey}
			          JOIN TORDER_MST_IC IC
			            ON SD.ICKEY = IC.ICKEY
			           AND SD.OWKEY = IC.OWKEY
			         WHERE 1 = 1 
			           --ADN IC.ICTYPE = '3' /* P-BOX 용기 */
			           AND SD.OWKEY = M.OWKEY
					   AND SD.SOHDKEY = M.SOHDKEY
					   AND SD.SODTKEY = M.SODTKEY
			      )

/* oms-socommon-sql-oracle.xml updateSOHDControl */ UPDATE TORDER_INFO_SO_HD M SET WKSTATUS = #{sowksts} , CNFRMDAY = (CASE WHEN #{sowksts} = '20' THEN TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD') ELSE '' END) , UPDATEDATE = #{interfaceDate} , UPDATEURKEY = #{userid} WHERE EXISTS ( SELECT 1 FROM ( SELECT SH.OWKEY , SH.SOHDKEY , SUM(CASE WHEN SD.WKSTATUS <> #{compSoStatus} THEN 1 ELSE 0 END) AS NONCOMPCNT FROM (
SELECT #{item.sohdkey} AS SOHDKEY
) VHD JOIN TORDER_INFO_SO_HD SH ON VHD.SOHDKEY = SH.SOHDKEY AND SH.OWKEY = #{owkey} JOIN TORDER_INFO_SO_DT SD ON SH.SOHDKEY = SD.SOHDKEY AND SH.OWKEY = SD.OWKEY JOIN TORDER_MST_ORTYPE OT ON SH.OWKEY = OT.OWKEY AND SH.ORDERTYPECD = OT.ORDERTYPECD WHERE SH.WKSTATUS <> #{cancelSoStatus} GROUP BY SH.OWKEY , SH.SOHDKEY ) TT WHERE TT.NONCOMPCNT > 0 AND TT.SOHDKEY = M.SOHDKEY AND TT.OWKEY = M.OWKEY )

	/* oms-socommon-sql-oracle.xml updateCODTControl */
	UPDATE TORDER_INFO_CO_DT M
	   SET WKSTATUS = #{cowksts}
	     , UPDATEDATE = #{interfaceDate}
	     , UPDATEURKEY = #{userid}
     WHERE EXISTS ( 
     				SELECT 1
			          FROM (

					        SELECT #{item.sohdkey} AS SOHDKEY 

			               ) VHD
			          JOIN TORDER_INFO_SO_DT SD
			            ON VHD.SOHDKEY = SD.SOHDKEY
			           AND SD.OWKEY = #{owkey}
			          JOIN TORDER_MST_IC IC
			            ON SD.ICKEY = IC.ICKEY
			           AND SD.OWKEY = IC.OWKEY
			         WHERE 1 = 1
			           --AND IC.ICTYPE = '3' /* P-BOX 용기 */
			           AND SD.OWKEY = M.OWKEY
					   AND SD.COHDKEY = M.COHDKEY
					   AND SD.CODTKEY = M.CODTKEY
			      )

/* oms-socommon-sql-oracle.xml updateCOHDControl */ UPDATE TORDER_INFO_CO_HD M SET WKSTATUS = #{cowksts} , UPDATEDATE = #{interfaceDate} , UPDATEURKEY = #{userid} WHERE EXISTS ( SELECT 1 FROM ( SELECT SH.OWKEY , SH.COHDKEY , SUM(CASE WHEN SD.WKSTATUS <> #{compCoStatus} THEN 1 ELSE 0 END) AS NONCOMPCNT FROM (
SELECT #{item.cohdkey} AS COHDKEY
) VHD JOIN TORDER_INFO_CO_HD SH ON VHD.COHDKEY = SH.COHDKEY AND SH.OWKEY = #{owkey} JOIN TORDER_INFO_CO_DT SD ON SH.COHDKEY = SD.COHDKEY AND SH.OWKEY = SD.OWKEY JOIN TORDER_MST_ORTYPE OT ON SH.OWKEY = OT.OWKEY AND SH.ORDERTYPECD = OT.ORDERTYPECD WHERE SH.WKSTATUS <> #{cancelCoStatus} GROUP BY SH.OWKEY , SH.COHDKEY ) TT WHERE TT.NONCOMPCNT > 0 AND TT.COHDKEY = M.COHDKEY AND TT.OWKEY = M.OWKEY )

	/* oms-socommon-sql-oracle.xml updateSODTErrControl */
	UPDATE TORDER_INFO_SO_DT M
	   SET WKSTATUS = #{sowksts}
	     , ORDERERRCD = #{controlErrorCode}
	     , ORDERERRCMT = REPLACE(#{controlErrorMessage}, #{param}, ICKEY || ':' || UOM)		     
	     , UPDATEDATE = #{interfaceDate}
	     , UPDATEURKEY = #{userid}
     WHERE EXISTS ( 
					SELECT 1
			          FROM (

					        SELECT #{item.sohdkey} AS SOHDKEY 

			               ) VHD
			          JOIN TORDER_INFO_SO_DT SD
			            ON VHD.SOHDKEY = SD.SOHDKEY
			           AND SD.OWKEY = #{owkey}
			          JOIN TORDER_MST_IC IC
			            ON SD.ICKEY = IC.ICKEY
			           AND SD.OWKEY = IC.OWKEY
			         WHERE 1 = 1 
			           --ADN IC.ICTYPE = '3' /* P-BOX 용기 */
			           AND SD.OWKEY = M.OWKEY
					   AND SD.SOHDKEY = M.SOHDKEY
					   AND SD.SODTKEY = M.SODTKEY
			      )

	/* oms-socommon-sql-oracle.xml updateSOHDErrControl */
	UPDATE TORDER_INFO_SO_HD M
	   SET WKSTATUS = #{sowksts}
	     , ORDERERRCD = #{controlErrorCode}
	     , ORDERERRCMT = REPLACE(#{controlErrorMessage}, #{param}, 'SO Detail')
	     , UPDATEDATE = #{interfaceDate}
	     , UPDATEURKEY = #{userid}
     WHERE EXISTS ( 
					SELECT 1
     			      FROM (
     			     	   SELECT SH.OWKEY
						        , SH.SOHDKEY
						        , SUM(CASE WHEN SD.WKSTATUS <> #{compSoStatus} THEN 1 ELSE 0 END) AS NONCOMPCNT
						     FROM (

							        SELECT #{item.sohdkey} AS SOHDKEY 

							       ) VHD
							  JOIN TORDER_INFO_SO_HD SH
							    ON VHD.SOHDKEY = SH.SOHDKEY
							   AND SH.OWKEY = #{owkey}					   
							  JOIN TORDER_INFO_SO_DT SD
							    ON SH.SOHDKEY = SD.SOHDKEY
							   AND SH.OWKEY = SD.OWKEY
							  JOIN TORDER_MST_ORTYPE OT
							    ON SH.OWKEY = OT.OWKEY
							   AND SH.ORDERTYPECD = OT.ORDERTYPECD
							 WHERE SH.WKSTATUS <> #{cancelSoStatus}
							 GROUP BY SH.OWKEY
						         , SH.SOHDKEY
     			     	   ) TT
     			     WHERE TT.NONCOMPCNT > 0
     			       AND TT.SOHDKEY = M.SOHDKEY
					   AND TT.OWKEY = M.OWKEY
			      )

	/* oms-socommon-sql-oracle.xml updateCODTErrControl */
	UPDATE TORDER_INFO_CO_DT M
	   SET WKSTATUS = #{cowksts}
	     , ORDERERRCD = #{controlErrorCode}
	     , ORDERERRCMT = REPLACE(#{controlErrorMessage}, #{param}, ICKEY || ':' || UNIT)		     
	     , UPDATEDATE = #{interfaceDate}
	     , UPDATEURKEY = #{userid}
     WHERE EXISTS ( 
     				SELECT 1
			          FROM (

					        SELECT #{item.sohdkey} AS SOHDKEY 

			               ) VHD
			          JOIN TORDER_INFO_SO_DT SD
			            ON VHD.SOHDKEY = SD.SOHDKEY
			           AND SD.OWKEY = #{owkey}
			          JOIN TORDER_MST_IC IC
			            ON SD.ICKEY = IC.ICKEY
			           AND SD.OWKEY = IC.OWKEY
			         WHERE 1 = 1
			           --AND IC.ICTYPE = '3' /* P-BOX 용기 */
			           AND SD.OWKEY = M.OWKEY
					   AND SD.COHDKEY = M.COHDKEY
					   AND SD.CODTKEY = M.CODTKEY
			      )

	/* oms-socommon-sql-oracle.xml updateCOHDErrControl */
	UPDATE TORDER_INFO_CO_HD M
	   SET WKSTATUS = #{cowksts}
	     , ORDERERRCD = #{controlErrorCode}
	     , ORDERERRCMT = REPLACE(#{controlErrorMessage}, #{param}, 'SO Detail')
	     , UPDATEDATE = #{interfaceDate}
	     , UPDATEURKEY = #{userid}
     WHERE EXISTS ( 
					SELECT 1
     			      FROM (
     			     	   SELECT SH.OWKEY
						        , SH.COHDKEY
						        , SUM(CASE WHEN SD.WKSTATUS <> #{compCoStatus} THEN 1 ELSE 0 END) AS NONCOMPCNT
						     FROM (

							        SELECT #{item.cohdkey} AS COHDKEY 

							       ) VHD
							  JOIN TORDER_INFO_CO_HD SH
							    ON VHD.COHDKEY = SH.COHDKEY
							   AND SH.OWKEY = #{owkey}					   
							  JOIN TORDER_INFO_CO_DT SD
							    ON SH.COHDKEY = SD.COHDKEY
							   AND SH.OWKEY = SD.OWKEY
							  JOIN TORDER_MST_ORTYPE OT
							    ON SH.OWKEY = OT.OWKEY
							   AND SH.ORDERTYPECD = OT.ORDERTYPECD
							 WHERE SH.WKSTATUS <> #{cancelCoStatus}
							 GROUP BY SH.OWKEY
						         , SH.COHDKEY
     			     	   ) TT
     			     WHERE TT.NONCOMPCNT > 0
     			       AND TT.COHDKEY = M.COHDKEY
					   AND TT.OWKEY = M.OWKEY
			      )

	/* oms-socommon-sql-oracle.xml updateSODTAutoComplete */
	UPDATE TORDER_INFO_SO_DT M
	   SET CNFRMQTY = EXPCTQTY
	     , WKSTATUS = #{sendSoStatus}
	     , UPDATEDATE = #{interfaceDate}
	     , UPDATEURKEY = #{userid}
     WHERE EXISTS ( 
				   SELECT 1
				     FROM (

					        SELECT #{item.sohdkey} AS SOHDKEY 

					       ) VHD
					  JOIN TORDER_INFO_SO_HD SH
					    ON VHD.SOHDKEY = SH.SOHDKEY
					   AND SH.OWKEY = #{owkey}
					  JOIN TORDER_MST_ORTYPE OT
					    ON SH.OWKEY = OT.OWKEY
					   AND SH.ORDERTYPECD = OT.ORDERTYPECD
					 WHERE COALESCE(OT.WMSPERFMANSYN, 'N') = 'N'
					   AND SH.SOHDKEY = M.SOHDKEY
					   AND SH.OWKEY = M.OWKEY
			      )

/* oms-socommon-sql-oracle.xml updateSOHDAutoComplete */ UPDATE TORDER_INFO_SO_HD M SET WKSTATUS = #{sendSoStatus} , UPDATEDATE = #{interfaceDate} , UPDATEURKEY = #{userid} WHERE EXISTS ( SELECT 1 FROM ( SELECT SH.OWKEY , SH.SOHDKEY , SUM(CASE WHEN SD.WKSTATUS <> #{compSoStatus} THEN 1 ELSE 0 END) AS NONCOMPCNT FROM (
SELECT #{item.sohdkey} AS SOHDKEY
) VHD JOIN TORDER_INFO_SO_HD SH ON VHD.SOHDKEY = SH.SOHDKEY AND SH.OWKEY = #{owkey} JOIN TORDER_INFO_SO_DT SD ON SH.SOHDKEY = SD.SOHDKEY AND SH.OWKEY = SD.OWKEY JOIN TORDER_MST_ORTYPE OT ON SH.OWKEY = OT.OWKEY AND SH.ORDERTYPECD = OT.ORDERTYPECD WHERE COALESCE(OT.WMSPERFMANSYN, 'N') = 'N' AND SH.WKSTATUS <> #{cancelSoStatus} GROUP BY SH.OWKEY , SH.SOHDKEY ) TT WHERE TT.NONCOMPCNT = 0 AND TT.SOHDKEY = M.SOHDKEY AND TT.OWKEY = M.OWKEY )

	/* oms-socommon-sql-oracle.xml updateCODTAutoComplete */
	UPDATE TORDER_INFO_CO_DT M
	   SET WKSTATUS = #{sendCoStatus}
	     , UPDATEDATE = #{interfaceDate}
	     , UPDATEURKEY = #{userid}
    WHERE EXISTS ( 
    			   SELECT 1
				     FROM (

					        SELECT #{item.cohdkey} AS COHDKEY 

					       ) VHD
					  JOIN TORDER_INFO_CO_HD CH
					    ON VHD.COHDKEY = CH.COHDKEY
					   AND CH.OWKEY = #{owkey}
					  JOIN TORDER_MST_ORTYPE OT
					    ON CH.OWKEY = OT.OWKEY
					   AND CH.ORDERTYPECD = OT.ORDERTYPECD
					 WHERE COALESCE(OT.WMSPERFMANSYN, 'N') = 'N'
					   AND CH.COHDKEY = M.COHDKEY
					   AND CH.OWKEY = M.OWKEY
				 )

/* oms-socommon-sql-oracle.xml updateCOHDAutoComplete */ UPDATE TORDER_INFO_CO_HD M SET WKSTATUS = #{sendCoStatus} , UPDATEDATE = #{interfaceDate} , UPDATEURKEY = #{userid} WHERE EXISTS ( SELECT 1 FROM ( SELECT CH.OWKEY , CH.COHDKEY , SUM(CASE WHEN CD.WKSTATUS <> #{compCoStatus} THEN 1 ELSE 0 END) AS NONCOMPCNT FROM (
SELECT #{item.cohdkey} AS COHDKEY
) VHD JOIN TORDER_INFO_CO_HD CH ON VHD.COHDKEY = CH.COHDKEY AND CH.OWKEY = #{owkey} JOIN TORDER_INFO_CO_DT CD ON CH.COHDKEY = CD.COHDKEY AND CH.OWKEY = CD.OWKEY JOIN TORDER_MST_ORTYPE OT ON CH.OWKEY = OT.OWKEY AND CH.ORDERTYPECD = OT.ORDERTYPECD WHERE COALESCE(OT.WMSPERFMANSYN, 'N') = 'N' AND CH.WKSTATUS <> #{cancelCoStatus} GROUP BY CH.OWKEY , CH.COHDKEY ) TT WHERE TT.NONCOMPCNT = 0 AND TT.COHDKEY = M.COHDKEY AND TT.OWKEY = M.OWKEY )

mapper.select:
/* oms-socommon-sql-oracle.xml selectSoHd */ SELECT HD.OWKEY ,HD.SOHDKEY ,HD.DLVYEXPCTDAY ,HD.ORDERISTDAY ,HD.CNFRMDAY ,HD.ORDERTYPECD ,HD.WKSTATUS ,HD.CTKEY ,HD.DLVYACKEY ,HD.STOREKEY ,HD.BILLKEY ,HD.PAYERKEY ,HD.ACKEY ,CASE WHEN HD.ACKEY IS NULL THEN TCT.CTNM ELSE AC.ACNM END AS ACNM ,HD.LOGGRPCD ,HD.ORGORDERKEY ,HD.FROMTOCTKEY ,HD.ICGRTYPE ,HD.ICGRKEY ,HD.POTYPE ,HD.RFRNCKEY ,HD.SALESEMPID ,HD.DLVYEMPID ,HD.EDIYN ,HD.CMT ,HD.CNLYN ,HD.CNLDATE ,HD.CNLEMPID ,HD.ORDERSNDYN ,HD.ORDERSNDDATE ,HD.ORDERSNDUSERID ,HD.COHDKEY ,HD.EXTORDERTYPECD ,HD.ORDERERRCD ,HD.ORDERERRCMT ,HD.ORDERRSNCD ,HD.ADDCMT01 ,HD.RECPNM ,HD.RECPADDRHD ,HD.RECPADDRDT ,HD.RECPZIPCD ,HD.RECPTEL01 ,HD.RECPTEL02 ,HD.BUYER ,HD.BUYERADDRHD ,HD.BUYERADDRDT ,HD.BUYERZIPCD ,HD.BUYERTEL01 ,HD.BUYERTEL02 ,HD.RECALLER ,HD.RECALLERADDRHD ,HD.RECALLERADDRDT ,HD.RECALLERZIPCD ,HD.RECALLERTEL01 ,HD.RECALLERTEL02 ,HD.RECALLERIYN ,HD.RIRSNCD ,HD.CLAIMNO ,HD.DLVYMETHDCD ,HD.DLVYMETHDDTCD ,HD.MALORDERDIV ,HD.NISYN ,HD.NISCNLRNGDIV ,HD.NISCFMYN ,HD.PAYMTCOMPLDAY ,HD.PARTERID ,HD.ACCESSKEY ,HD.ADDCMT02 ,HD.ADDCMT03 ,HD.SHMISTNO ,HD.IFYN ,HD.OPENCHKYN ,HD.FRONTYN ,HD.INSERTDATE ,HD.INSERTURKEY ,HD.UPDATEDATE ,HD.UPDATEURKEY ,CH.IFID FROM TORDER_INFO_SO_HD HD INNER JOIN TORDER_INFO_CO_HD CH ON HD.OWKEY = CH.OWKEY AND HD.COHDKEY = CH.COHDKEY INNER JOIN (
SELECT #{item.sohdkey} AS SOHDKEY , #{item.ctkey} AS CTKEY , #{item.ackey} AS ACKEY , #{item.owkey} AS OWKEY , #{item.ordertypecd} AS ORDERTYPECD ,#{item.dlvyackey} AS DLVYACKEY
) VHD ON HD.SOHDKEY = VHD.SOHDKEY AND HD.OWKEY = VHD.OWKEY LEFT JOIN TORDER_MST_AC AC ON HD.OWKEY = AC.OWKEY AND HD.ACKEY = AC.ACKEY LEFT JOIN TORDER_MST_CT TCT ON HD.FROMTOCTKEY = TCT.CTKEY

/* oms-socommon-sql-oracle.xml selectSoDt */ SELECT DT.OWKEY /*화주코드*/ ,DT.SOHDKEY /*S/O번호*/ ,DT.SODTKEY /*S/O상세번호*/ ,DT.ICKEY /*모상품코드*/ ,DT.OLNICKEY /*자상품코드*/ ,DT.ICUTKEY /*제품단위코드*/ ,DT.UOM /*주문단위*/ ,DT.INITQTY /*초기수량(EA)*/ ,DT.EXPCTQTY /*예정수량(EA)*/ ,DT.CNFRMQTY /*확정수량(EA)*/ ,DT.SNDQTY /*전송수량(EA)*/ ,DT.DLVYEXPCTDAY /*배송예정일자*/ ,DT.ORDERISTDAY /*지시일자*/ ,DT.OBAMT /*출고금액*/ ,DT.VOL /*총부피*/ ,DT.VOLUNIT /*부피단위*/ ,DT.LOGGRPCD /*상/저온 구분*/ ,DT.CMT /*비고*/ ,DT.PRDCTLOT /*생산 LOT*/ ,DT.PRDCTDAY /*생산일자*/ ,DT.WKSTATUS /*작업(주문) 상태*/ ,DT.RFRNCKEY /*이전참조문서번호*/ ,DT.RFRNCDTKEY /*이전참조상세번호*/ ,DT.ORGORDERKEY /*외부주문번호*/ ,DT.ORGORDERDTKEY /*외부주문상세번호*/ ,DT.CNLYN /*주문취소여부*/ ,DT.NISCMT /*결품사유*/ ,DT.RICMT /*반품사유*/ ,DT.COHDKEY /*CO주문번호*/ ,DT.CODTKEY /*CO주문상세번호*/ ,DT.ORDERERRCD /*주문오류 코드*/ ,DT.ORDERERRCMT /*주문생성 오류비고*/ ,DT.ICGRKEY /*상품그룹*/ ,DT.ICGRTYPE /*상품그룹유형*/ ,DT.SPEC /*규격*/ ,DT.SHMISTNO /*출하지시번호*/ ,DT.INSERTDATE /*입력 일시*/ ,DT.INSERTURKEY /*입력 사용자 ID*/ ,DT.UPDATEDATE /*수정 일시*/ ,DT.UPDATEURKEY /*수정 사용자 ID*/ ,VHD.ORDERTYPECD ,VHD.CTKEY FROM TORDER_INFO_SO_DT DT INNER JOIN (
SELECT #{item.sohdkey} AS SOHDKEY , #{item.ctkey} AS CTKEY , #{item.ackey} AS ACKEY , #{item.owkey} AS OWKEY , #{item.ordertypecd} AS ORDERTYPECD ,#{item.dlvyackey} AS DLVYACKEY
) VHD ON DT.SOHDKEY = VHD.SOHDKEY AND DT.OWKEY = VHD.OWKEY

SELECT B.OWKEY, B.CTKEY, B.SOHDKEY, C.DLVRYCORPCD, C.WBLNO FROM TORDER_INFO_CO_HD A INNER JOIN TORDER_INFO_SO_HD B ON A.OWKEY = B.OWKEY AND A.COHDKEY = B.COHDKEY INNER JOIN TORDER_INTF_MAL_RET_WBL C ON A.IFID = C.IFID::TEXT WHERE 1 = 1 AND A.EXTORDERTYPECD = #{extordertypecd}
AND A.IFID IN
#{ifid}

SELECT B.OWKEY, B.CTKEY, B.SOHDKEY, C.IMGSEQ, C.IMGURL FROM TORDER_INFO_CO_HD A INNER JOIN TORDER_INFO_SO_HD B ON A.OWKEY = B.OWKEY AND A.COHDKEY = B.COHDKEY INNER JOIN TORDER_INTF_MAL_RET_FILE C ON A.IFID = C.IFID::TEXT WHERE 1 = 1 AND A.EXTORDERTYPECD = #{extordertypecd}
AND A.IFID IN
#{ifid}

mapper.insert:
/* oms-socommon-sql-oracle.xml insertWmsPerformance*/ INSERT INTO TORDER_INFO_WMS_PERFORMANCE ( OWKEY /*화주코드*/ , SOHDKEY /*S/O번호*/ , SODTKEY /*S/O상세번호*/ , WORKSEQ /*재전송 SEQ*/ , ICKEY /*상품코드*/ , CFQTY /*확정수량*/ , UOM /*수량단위*/ , EXPIREDATE /*유통기한*/ , CLOSEYN /*마감여부*/ , REPROCESSYN /*재전송여부*/ , SAPSENDYN , EXTERNORDERKEY /*외부주문번호*/ , EXTERNORDERDETAILKEY /*외부주문상세*/ , INSERTDATE /*입력 일시*/ , INSERTURKEY /*입력 사용자 ID*/ , UPDATEDATE /*수정 일시*/ , UPDATEURKEY /*수정 사용자 ID*/ ) SELECT XXX.OWKEY /*화주코드*/ , XXX.SOHDKEY /*S/O번호*/ , XXX.SODTKEY /*S/O상세번호*/ , XXX.WORKSEQ /*재전송 SEQ*/ , XXX.ICKEY /*상품코드*/ , XXX.CFQTY /*확정수량*/ , XXX.UOM /*수량단위*/ , XXX.EXPIREDATE /*유통기한*/ , XXX.CLOSEYN /*마감여부*/ , XXX.REPROCESSYN /*재전송여부*/ , 'N' AS SAPSENDYN , XXX.EXTERNORDERKEY /*외부주문번호*/ , XXX.EXTERNORDERDETAILKEY /*외부주문상세*/ , #{sysdate} AS INSERTDATE /*입력 일시*/ , #{userid} AS INSERTURKEY /*입력 사용자 ID*/ , #{sysdate} AS UPDATEDATE /*수정 일시*/ , #{userid} AS UPDATEURKEY /*수정 사용자 ID*/ FROM ( SELECT X.OWKEY /*화주코드*/ , X.SOHDKEY /*S/O번호*/ , X.SODTKEY /*S/O상세번호*/ , X.ICKEY /*상품코드*/ , X.CFQTY /*확정수량*/ , X.UOM /*수량단위*/ , X.EXPIREDATE /*유통기한*/ , X.CLOSEYN /*마감여부*/ , X.REPROCESSYN /*재전송여부*/ , X.EXTERNORDERKEY /*외부주문번호*/ , X.EXTERNORDERDETAILKEY /*외부주문상세*/ , CASE WHEN SHD.WKSTATUS IS NULL THEN -10 /* SO주문이 존재하지 않은 경우 */ WHEN SHD.WKSTATUS IN ('00' ,'05' ,'20', '40' ) THEN -20 /* 작업 진행 중인 상태 제외함*/ WHEN COALESCE(HD.WKSTATUS, 'ING') IN ( 'SEND' , 'CANCEL' , 'ERROR' , 'RECEIPT') THEN -20 /* 실적이 넘어오면 안되는상황 */ WHEN COALESCE(Z.DELYN, 'N') ='Y' AND X.CLOSEYN ='N' AND COALESCE(X.REPROCESSYN, 'N') ='Y' THEN -30 /* PROCESS 오류 마감 이후 재처리가 가능 */ WHEN COALESCE(Z.DELYN, 'N') ='Y' THEN Z.WORKSEQ +1 /* 이전 작업이 취소이면 처리 대상임 */ WHEN Z.DELYN IS NULL THEN 0 /* 최초처리 건 */ -- WHEN COALESCE(Z.DELYN, 'N') ='N' AND Z.CLOSEYN ='N' AND X.CLOSEYN ='N' THEN Z.WORKSEQ +1 /* 수량 업데이트 건 INSERT에서 처리안함*/ -- WHEN COALESCE(Z.DELYN, 'N') ='N' AND Z.CLOSEYN ='N' AND X.CLOSEYN ='Y' THEN Z.WORKSEQ +1 /* 수량 업데이트 건 INSERT에서 처리안함*/ WHEN COALESCE(Z.DELYN, 'N') ='N' AND COALESCE(Z.CLOSEYN, 'N') ='Y' AND X.CLOSEYN ='Y' AND COALESCE(X.REPROCESSYN, 'N') ='Y' THEN -40 /* 마감 건 취소 처리후 처리가능 */ WHEN COALESCE(Z.DELYN, 'N') ='N' AND COALESCE(Z.CLOSEYN, 'N') ='Y' AND X.CLOSEYN ='Y' THEN -50 /* 마감 중복건 */ ELSE - 999::INTEGER END AS WORKSEQ FROM TORDER_INTF_WMS_PERFORMANCE X LEFT OUTER JOIN TORDER_INFO_SO_HD SH ON X.OWKEY = SH.OWKEY AND X.SOHDKEY = SH.SOHDKEY LEFT OUTER JOIN TORDER_INFO_SO_DT SHD ON X.OWKEY = SHD.OWKEY AND X.SOHDKEY = SHD.SOHDKEY AND X.SODTKEY = SHD.SODTKEY LEFT OUTER JOIN TORDER_INFO_CO_DT HD ON SHD.OWKEY = HD.OWKEY AND SHD.CUSTOMERORDERKEY = HD.CUSTOMERORDERKEY AND SHD.CUSTOMERORDERDTKEY = HD.CUSTOMERORDERDTKEY LEFT OUTER JOIN TORDER_MST_ORTYPE OT ON SH.OWKEY = OT.OWKEY AND SH.OR_TYPE_CD = OT.OR_TYPE_CD LEFT OUTER JOIN ( SELECT OWKEY ,SOHDKEY ,SODTKEY ,MAX(WORKSEQ) AS WORKSEQ ,MAX(CLOSEYN) AS CLOSEYN ,MAX(REPROCESSYN) AS REPROCESSYN ,MAX(SAPSENDYN) AS SAPSENDYN ,MAX(DELYN) AS DELYN FROM ( SELECT A.OWKEY /*화주코드*/ , A.SOHDKEY /*S/O번호*/ , A.SODTKEY /*S/O상세번호*/ , MAX(A.WORKSEQ) OVER ( PARTITION BY A.OWKEY ,A.SOHDKEY , A.SODTKEY) WORKSEQ , FIRST_VALUE(A.CLOSEYN) OVER ( PARTITION BY A.OWKEY, A.SOHDKEY, A.SODTKEY ORDER BY WORKSEQ DESC ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING) CLOSEYN , FIRST_VALUE(A.REPROCESSYN) OVER ( PARTITION BY A.OWKEY, A.SOHDKEY, A.SODTKEY ORDER BY WORKSEQ DESC ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING) REPROCESSYN , FIRST_VALUE(A.SAPSENDYN) OVER ( PARTITION BY A.OWKEY, A.SOHDKEY, A.SODTKEY ORDER BY WORKSEQ DESC ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING) SAPSENDYN , FIRST_VALUE(A.DELYN) OVER ( PARTITION BY A.OWKEY, A.SOHDKEY, A.SODTKEY ORDER BY WORKSEQ DESC ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING) DELYN FROM TORDER_INFO_WMS_PERFORMANCE A INNER JOIN TORDER_INTF_WMS_PERFORMANCE B ON A.OWKEY = B.OWKEY AND A.SOHDKEY = B.SOHDKEY AND A.SODTKEY = B.SODTKEY and B.INTERFACE_ID =#{interfaceId} ) GROUP BY OWKEY , SOHDKEY ,SODTKEY ) Z ON X.OWKEY = Z.OWKEY AND X.SOHDKEY = Z.SOHDKEY AND X.SODTKEY = Z.SODTKEY WHERE X.INTERFACE_ID = #{interfaceId} AND (OT.OWSPCVERIFICATION IS NULL OR OT.OWSPCVERIFICATION!='MULTIPLE') AND OT.COMBINATIONYN = 'N' ) XXX
LEFT OUTER JOIN ( SELECT OWKEY , SOHDKEY FROM (
SELECT #{item.soHdkey} AS SOHDKEY, #{item.owkey} AS OWKEY
) EL GROUP BY OWKEY, SOHDKEY ) ERR ON XXX.OWKEY = ERR.OWKEY AND XXX.SOHDKEY = ERR.SOHDKEY WHERE ERR.SOHDKEY IS NULL

/* oms-socommon-sql-oracle.xml insertWmsPerformanceMultiple*/ INSERT INTO TORDER_INFO_WMS_PERFORMANCE ( OWKEY /*화주코드*/ , SOHDKEY /*S/O번호*/ , SODTKEY /*S/O상세번호*/ , WORKSEQ /*재전송 SEQ*/ , ICKEY /*상품코드*/ , CFQTY /*확정수량*/ , UOM /*수량단위*/ , EXPIREDATE /*유통기한*/ , CLOSEYN /*마감여부*/ , REPROCESSYN /*재전송여부*/ , SAPSENDYN , EXTERNORDERKEY /*외부주문번호*/ , EXTERNORDERDETAILKEY /*외부주문상세*/ , INSERTDATE /*입력 일시*/ , INSERTURKEY /*입력 사용자 ID*/ , UPDATEDATE /*수정 일시*/ , UPDATEURKEY /*수정 사용자 ID*/ ) SELECT XXX.OWKEY /*화주코드*/ , XXX.SOHDKEY /*S/O번호*/ , XXX.SODTKEY /*S/O상세번호*/ , XXX.WORKSEQ /*재전송 SEQ*/ , XXX.ICKEY /*상품코드*/ , XXX.CFQTY /*확정수량*/ , XXX.UOM /*수량단위*/ , XXX.EXPIREDATE /*유통기한*/ , XXX.CLOSEYN /*마감여부*/ , XXX.REPROCESSYN /*재전송여부*/ , 'N' AS SAPSENDYN , XXX.EXTERNORDERKEY /*외부주문번호*/ , XXX.EXTERNORDERDETAILKEY /*외부주문상세*/ , #{sysdate} AS INSERTDATE /*입력 일시*/ , #{userid} AS INSERTURKEY /*입력 사용자 ID*/ , #{sysdate} AS UPDATEDATE /*수정 일시*/ , #{userid} AS UPDATEURKEY /*수정 사용자 ID*/ FROM ( SELECT X.OWKEY /*화주코드*/ , X.SOHDKEY /*S/O번호*/ , SHD.SODTKEY /*S/O상세번호*/ , X.ICKEY /*상품코드*/ , CASE WHEN SHD.OB_COSTPRICE=0 THEN SHD.BONUS_IC_RATE ELSE SHD.IC_RATE END * (X.CFQTY / (SHD.IC_RATE + SHD.BONUS_IC_RATE)) AS CFQTY , IU.ICUNITTYPE AS UOM /*수량단위*/ , X.EXPIREDATE /*유통기한*/ , X.CLOSEYN /*마감여부*/ , X.REPROCESSYN /*재전송여부*/ , X.EXTERNORDERKEY /*외부주문번호*/ , SHD.EXTERNORDERDETAILKEY /*외부주문상세*/ , CASE WHEN SHD.WKSTATUS IS NULL THEN -10 /* SO주문이 존재하지 않은 경우 */ WHEN SHD.WKSTATUS IN ('00' ,'05' ,'20', '40' ) THEN -20 /* 작업 진행 중인 상태 제외함*/ WHEN COALESCE(HD.WKSTATUS, 'ING') IN ( 'SEND' , 'CANCEL' , 'ERROR' , 'RECEIPT') THEN -20 /* 실적이 넘어오면 안되는상황 */ WHEN COALESCE(Z.DELYN, 'N') ='Y' AND X.CLOSEYN ='N' AND COALESCE(X.REPROCESSYN, 'N') ='Y' THEN -30 /* PROCESS 오류 마감 이후 재처리가 가능 */ WHEN COALESCE(Z.DELYN, 'N') ='Y' THEN Z.WORKSEQ +1 /* 이전 작업이 취소이면 처리 대상임 */ WHEN Z.DELYN IS NULL THEN 0 /* 최초처리 건 */ -- WHEN COALESCE(Z.DELYN, 'N') ='N' AND Z.CLOSEYN ='N' AND X.CLOSEYN ='N' THEN Z.WORKSEQ +1 /* 수량 업데이트 건 INSERT에서 처리안함*/ -- WHEN COALESCE(Z.DELYN, 'N') ='N' AND Z.CLOSEYN ='N' AND X.CLOSEYN ='Y' THEN Z.WORKSEQ +1 /* 수량 업데이트 건 INSERT에서 처리안함*/ WHEN COALESCE(Z.DELYN, 'N') ='N' AND COALESCE(Z.CLOSEYN, 'N') ='Y' AND X.CLOSEYN ='Y' AND COALESCE(X.REPROCESSYN, 'N') ='Y' THEN -40 /* 마감 건 취소 처리후 처리가능 */ WHEN COALESCE(Z.DELYN, 'N') ='N' AND COALESCE(Z.CLOSEYN, 'N') ='Y' AND X.CLOSEYN ='Y' THEN -50 /* 마감 중복건 */ ELSE - 999::INTEGER END AS WORKSEQ FROM TORDER_INTF_WMS_PERFORMANCE X LEFT OUTER JOIN TORDER_INFO_SO_HD SH ON X.OWKEY = SH.OWKEY AND X.SOHDKEY = SH.SOHDKEY LEFT OUTER JOIN TORDER_INFO_SO_DT SHD ON X.OWKEY = SHD.OWKEY AND X.SOHDKEY = SHD.SOHDKEY AND X.ICKEY = SHD.ICKEY LEFT OUTER JOIN TADMIN_MST_ICUTXTYPE IU ON SHD.OWKEY = IU.OWKEY AND SHD.ICUTKEY = IU.ICUNITKEY AND SHD.UOM = IU.ICUNITTYPE LEFT OUTER JOIN TORDER_MST_ORTYPE OT ON SH.OWKEY = OT.OWKEY AND SH.OR_TYPE_CD = OT.OR_TYPE_CD LEFT OUTER JOIN TORDER_INFO_CO_DT HD ON SHD.OWKEY = HD.OWKEY AND SHD.CUSTOMERORDERKEY = HD.CUSTOMERORDERKEY AND SHD.CUSTOMERORDERDTKEY = HD.CUSTOMERORDERDTKEY LEFT OUTER JOIN ( SELECT OWKEY ,SOHDKEY ,SODTKEY ,MAX(WORKSEQ) AS WORKSEQ ,MAX(CLOSEYN) AS CLOSEYN ,MAX(REPROCESSYN) AS REPROCESSYN ,MAX(SAPSENDYN) AS SAPSENDYN ,MAX(DELYN) AS DELYN FROM ( SELECT A.OWKEY /*화주코드*/ , A.SOHDKEY /*S/O번호*/ , A.SODTKEY /*S/O상세번호*/ , MAX(A.WORKSEQ) OVER ( PARTITION BY A.OWKEY ,A.SOHDKEY , A.SODTKEY) WORKSEQ , FIRST_VALUE(A.CLOSEYN) OVER ( PARTITION BY A.OWKEY, A.SOHDKEY, A.SODTKEY ORDER BY WORKSEQ DESC ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING) CLOSEYN , FIRST_VALUE(A.REPROCESSYN) OVER ( PARTITION BY A.OWKEY, A.SOHDKEY, A.SODTKEY ORDER BY WORKSEQ DESC ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING) REPROCESSYN , FIRST_VALUE(A.SAPSENDYN) OVER ( PARTITION BY A.OWKEY, A.SOHDKEY, A.SODTKEY ORDER BY WORKSEQ DESC ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING) SAPSENDYN , FIRST_VALUE(A.DELYN) OVER ( PARTITION BY A.OWKEY, A.SOHDKEY, A.SODTKEY ORDER BY WORKSEQ DESC ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING) DELYN FROM TORDER_INFO_WMS_PERFORMANCE A INNER JOIN TORDER_INTF_WMS_PERFORMANCE B ON A.OWKEY = B.OWKEY AND A.SOHDKEY = B.SOHDKEY AND A.ICKEY = B.ICKEY AND B.INTERFACE_ID =#{interfaceId} AND B.REQUESTDT = #{requestDt} ) GROUP BY OWKEY , SOHDKEY ,SODTKEY ) Z ON SHD.OWKEY = Z.OWKEY AND SHD.SOHDKEY = Z.SOHDKEY AND SHD.SODTKEY = Z.SODTKEY WHERE X.INTERFACE_ID = #{interfaceId} AND OT.OWSPCVERIFICATION IS NOT NULL AND OT.OWSPCVERIFICATION='MULTIPLE' ) XXX
LEFT OUTER JOIN ( SELECT OWKEY , SOHDKEY FROM (
SELECT #{item.soHdkey} AS SOHDKEY, #{item.owkey} AS OWKEY
) EL GROUP BY OWKEY, SOHDKEY ) ERR ON XXX.OWKEY = ERR.OWKEY AND XXX.SOHDKEY = ERR.SOHDKEY WHERE ERR.SOHDKEY IS NULL

/* oms-socommon-sql-oracle.xml insertWmsPerformanceCombination*/ INSERT INTO TORDER_INFO_WMS_PERFORMANCE ( OWKEY /*화주코드*/ , SOHDKEY /*S/O번호*/ , SODTKEY /*S/O상세번호*/ , WORKSEQ /*재전송 SEQ*/ , ICKEY /*상품코드*/ , CFQTY /*확정수량*/ , UOM /*수량단위*/ , EXPIREDATE /*유통기한*/ , CLOSEYN /*마감여부*/ , REPROCESSYN /*재전송여부*/ , SAPSENDYN , EXTERNORDERKEY /*외부주문번호*/ , EXTERNORDERDETAILKEY /*외부주문상세*/ , INSERTDATE /*입력 일시*/ , INSERTURKEY /*입력 사용자 ID*/ , UPDATEDATE /*수정 일시*/ , UPDATEURKEY /*수정 사용자 ID*/ ) SELECT XXX.OWKEY /*화주코드*/ , XXX.SOHDKEY /*S/O번호*/ , XXX.SODTKEY /*S/O상세번호*/ , XXX.WORKSEQ /*재전송 SEQ*/ , XXX.ICKEY /*상품코드*/ , CASE WHEN XXX.LASTRN = 1 THEN GREATEST(0, XXX.CFQTY - SUM(XXX.EXQTY) OVER(PARTITION BY XXX.SOHDKEY, XXX.ICKEY ORDER BY XXX.SODTKEY ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING)) WHEN XXX.CFQTY >= XXX.CFSUBQTY THEN EXQTY WHEN XXX.CFQTY < XXX.CFSUBQTY AND CFQTY > (XXX.CFSUBQTY - XXX.EXQTY) THEN XXX.CFQTY - (XXX.CFSUBQTY - XXX.EXQTY) ELSE 0 END AS CFQTY /*확정수량*/ , XXX.UOM /*수량단위*/ , XXX.EXPIREDATE /*유통기한*/ , XXX.CLOSEYN /*마감여부*/ , XXX.REPROCESSYN /*재전송여부*/ , 'N' AS SAPSENDYN , XXX.EXTERNORDERKEY /*외부주문번호*/ , XXX.EXTERNORDERDETAILKEY /*외부주문상세*/ , #{sysdate} AS INSERTDATE /*입력 일시*/ , #{userid} AS INSERTURKEY /*입력 사용자 ID*/ , #{sysdate} AS UPDATEDATE /*수정 일시*/ , #{userid} AS UPDATEURKEY /*수정 사용자 ID*/ FROM ( SELECT X.OWKEY /*화주코드*/ , X.SOHDKEY /*S/O번호*/ , SHD.SODTKEY /*S/O상세번호*/ , X.ICKEY /*상품코드*/ , X.CFQTY , SHD.EXQTY /*예정수량*/ , SUM(SHD.EXQTY) OVER(PARTITION BY X.SOHDKEY, X.ICKEY ORDER BY SHD.SODTKEY) AS CFSUBQTY , ROW_NUMBER() OVER (PARTITION BY X.SOHDKEY, X.ICKEY ORDER BY SHD.SODTKEY DESC) AS LASTRN /*마지막라인*/ , IU.ICUNITTYPE AS UOM /*수량단위*/ , X.EXPIREDATE /*유통기한*/ , X.CLOSEYN /*마감여부*/ , X.REPROCESSYN /*재전송여부*/ , X.EXTERNORDERKEY /*외부주문번호*/ , SHD.EXTERNORDERDETAILKEY /*외부주문상세*/ , CASE WHEN SHD.WKSTATUS IS NULL THEN -10 /* SO주문이 존재하지 않은 경우 */ WHEN SHD.WKSTATUS IN ('00' ,'05' ,'20', '40' ) THEN -20 /* 작업 진행 중인 상태 제외함*/ WHEN COALESCE(HD.WKSTATUS, 'ING') IN ( 'SEND' , 'CANCEL' , 'ERROR' , 'RECEIPT') THEN -20 /* 실적이 넘어오면 안되는상황 */ WHEN COALESCE(Z.DELYN, 'N') ='Y' AND X.CLOSEYN ='N' AND COALESCE(X.REPROCESSYN, 'N') ='Y' THEN -30 /* PROCESS 오류 마감 이후 재처리가 가능 */ WHEN COALESCE(Z.DELYN, 'N') ='Y' THEN Z.WORKSEQ +1 /* 이전 작업이 취소이면 처리 대상임 */ WHEN Z.DELYN IS NULL THEN 0 /* 최초처리 건 */ -- WHEN COALESCE(Z.DELYN, 'N') ='N' AND Z.CLOSEYN ='N' AND X.CLOSEYN ='N' THEN Z.WORKSEQ +1 /* 수량 업데이트 건 INSERT에서 처리안함*/ -- WHEN COALESCE(Z.DELYN, 'N') ='N' AND Z.CLOSEYN ='N' AND X.CLOSEYN ='Y' THEN Z.WORKSEQ +1 /* 수량 업데이트 건 INSERT에서 처리안함*/ WHEN COALESCE(Z.DELYN, 'N') ='N' AND COALESCE(Z.CLOSEYN, 'N') ='Y' AND X.CLOSEYN ='Y' AND COALESCE(X.REPROCESSYN, 'N') ='Y' THEN -40 /* 마감 건 취소 처리후 처리가능 */ WHEN COALESCE(Z.DELYN, 'N') ='N' AND COALESCE(Z.CLOSEYN, 'N') ='Y' AND X.CLOSEYN ='Y' THEN -50 /* 마감 중복건 */ ELSE - 999::INTEGER END AS WORKSEQ FROM TORDER_INTF_WMS_PERFORMANCE X LEFT OUTER JOIN TORDER_INFO_SO_HD SH ON X.OWKEY = SH.OWKEY AND X.SOHDKEY = SH.SOHDKEY LEFT OUTER JOIN TORDER_INFO_SO_DT SHD ON X.OWKEY = SHD.OWKEY AND X.SOHDKEY = SHD.SOHDKEY AND X.ICKEY = SHD.ICKEY LEFT OUTER JOIN TADMIN_MST_ICUTXTYPE IU ON SHD.OWKEY = IU.OWKEY AND SHD.ICUTKEY = IU.ICUNITKEY AND SHD.UOM = IU.ICUNITTYPE LEFT OUTER JOIN TORDER_MST_ORTYPE OT ON SH.OWKEY = OT.OWKEY AND SH.OR_TYPE_CD = OT.OR_TYPE_CD LEFT OUTER JOIN TORDER_INFO_CO_DT HD ON SHD.OWKEY = HD.OWKEY AND SHD.CUSTOMERORDERKEY = HD.CUSTOMERORDERKEY AND SHD.CUSTOMERORDERDTKEY = HD.CUSTOMERORDERDTKEY LEFT OUTER JOIN ( SELECT OWKEY ,SOHDKEY ,SODTKEY ,MAX(WORKSEQ) AS WORKSEQ ,MAX(CLOSEYN) AS CLOSEYN ,MAX(REPROCESSYN) AS REPROCESSYN ,MAX(SAPSENDYN) AS SAPSENDYN ,MAX(DELYN) AS DELYN FROM ( SELECT A.OWKEY /*화주코드*/ , A.SOHDKEY /*S/O번호*/ , A.SODTKEY /*S/O상세번호*/ , MAX(A.WORKSEQ) OVER ( PARTITION BY A.OWKEY ,A.SOHDKEY , A.SODTKEY) WORKSEQ , FIRST_VALUE(A.CLOSEYN) OVER ( PARTITION BY A.OWKEY, A.SOHDKEY, A.SODTKEY ORDER BY WORKSEQ DESC ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING) CLOSEYN , FIRST_VALUE(A.REPROCESSYN) OVER ( PARTITION BY A.OWKEY, A.SOHDKEY, A.SODTKEY ORDER BY WORKSEQ DESC ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING) REPROCESSYN , FIRST_VALUE(A.SAPSENDYN) OVER ( PARTITION BY A.OWKEY, A.SOHDKEY, A.SODTKEY ORDER BY WORKSEQ DESC ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING) SAPSENDYN , FIRST_VALUE(A.DELYN) OVER ( PARTITION BY A.OWKEY, A.SOHDKEY, A.SODTKEY ORDER BY WORKSEQ DESC ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING) DELYN FROM TORDER_INFO_WMS_PERFORMANCE A INNER JOIN TORDER_INTF_WMS_PERFORMANCE B ON A.OWKEY = B.OWKEY AND A.SOHDKEY = B.SOHDKEY AND A.ICKEY = B.ICKEY AND B.INTERFACE_ID =#{interfaceId} AND B.REQUESTDT = #{requestDt} ) GROUP BY OWKEY , SOHDKEY ,SODTKEY ) Z ON SHD.OWKEY = Z.OWKEY AND SHD.SOHDKEY = Z.SOHDKEY AND SHD.SODTKEY = Z.SODTKEY WHERE X.INTERFACE_ID = #{interfaceId} AND (OT.OWSPCVERIFICATION IS NULL OR OT.OWSPCVERIFICATION!='MULTIPLE') AND OT.COMBINATIONYN = 'Y' ) XXX
LEFT OUTER JOIN ( SELECT OWKEY , SOHDKEY FROM (
SELECT #{item.soHdkey} AS SOHDKEY, #{item.owkey} AS OWKEY
) EL GROUP BY OWKEY, SOHDKEY ) ERR ON XXX.OWKEY = ERR.OWKEY AND XXX.SOHDKEY = ERR.SOHDKEY WHERE ERR.SOHDKEY IS NULL

/* oms-socommon-sql-oracle.xml insertWmsPerformanceIf */ INSERT INTO TORDER_INTF_WMS_PERFORMANCE ( OWKEY /*화주코드*/ ,SOHDKEY /*S/O번호*/ ,SODTKEY /*S/O상세번호*/ ,ICKEY /*상품코드*/ ,CFQTY /*확정수량*/ ,UOM /*수량단위*/ ,CLOSEYN /*마감여부*/ ,REPROCESSYN /*재전송여부*/ ,EXPIREDATE /*유통기한*/ ,EXTERNORDERKEY /*외부주문번호*/ ,EXTERNORDERDETAILKEY /*외부주문상세번호*/ ,REQUESTDT /*요청일자*/ ,INTERFACE_ID /*인터페이스 마스터 ID*/ ,INSERTDATE /*입력 일시*/ ,INSERTURKEY /*입력 사용자 ID*/ ,UPDATEDATE /*수정 일시*/ ,UPDATEURKEY /*수정 사용자 ID*/ ) SELECT X.OWKEY /*화주코드*/ ,X.SOHDKEY /*S/O번호*/ ,X.SODTKEY /*S/O상세번호*/ ,X.ICKEY ,X.CFQTY /*확정수량*/ ,X.UOM /*수량단위*/ ,X.CLOSEYN /*마감여부*/ ,X.REPROCESSYN /*재전송여부*/ ,X.EXPIREDATE /*유통기한*/ ,X.EXTERNORDERKEY /*외부주문번호*/ ,X.EXTERNORDERDETAILKEY /*외부주문상세번호*/ ,#{requestDt} /*요청일자*/ ,#{interfaceId} /*인터페이스 마스터 ID*/ ,#{sysdate} /*입력 일시*/ ,#{userid} /*입력 사용자 ID*/ ,#{sysdate} /*수정 일시*/ ,#{userid} /*수정 사용자 ID*/ FROM (
SELECT #{item.owkey} OWKEY ,#{item.soHdkey} SOHDKEY ,#{item.soDtkey} SODTKEY ,#{item.ickey} ICKEY ,#{item.cfqty} CFQTY ,#{item.expiredate} EXPIREDATE /*유통기한*/ ,#{item.uom} UOM ,#{item.closeyn} CLOSEYN ,#{item.reprocessyn} REPROCESSYN ,#{item.externorderkey} EXTERNORDERKEY ,#{item.externorderdetailkey} EXTERNORDERDETAILKEY
) X

/* oms-socommon-sql-oracle.xml insertTmsPerformanceIf */ INSERT INTO TORDER_INTF_TMS_PERFORMANCE ( OWKEY /*화주코드*/ ,SOHDKEY /*S/O번호*/ ,SODTKEY /*S/O상세번호*/ ,CARRCD /*운송사코드*/ ,TRPSEQNUM /*계획번호*/ ,VEHICLENUM /*차량번호*/ ,DCKEY /*회차*/ ,EQUIPTYPDESC /*차량종류*/ ,DELIVERY_PERSON_ID ,ICKEY /*상품코드*/ ,CFQTY /*확정수량*/ ,UOM /*수량단위*/ ,CLOSEYN /*마감여부*/ ,REPROCESSYN /*재전송여부*/ ,EXTERNORDERKEY /*외부주문번호*/ ,EXTERNORDERDETAILKEY /*외부주문상세번호*/ ,REQUESTDT /*요청일자*/ ,INTERFACE_ID /*인터페이스 마스터 ID*/ ,INSERTDATE /*입력 일시*/ ,INSERTURKEY /*입력 사용자 ID*/ ,UPDATEDATE /*수정 일시*/ ,UPDATEURKEY /*수정 사용자 ID*/ ) SELECT COALESCE(X.OWKEY, SH.OWKEY) AS OWKEY /*화주코드*/ ,X.SOHDKEY /*S/O번호*/ ,X.SODTKEY /*S/O상세번호*/ ,X.CARRCD /*운송사코드*/ ,X.TRPSEQNUM /*계획번호*/ ,X.VEHICLENUM /*차량번호*/ ,X.DCKEY /*회차*/ ,X.EQUIPTYPDESC /*차량종류*/ ,X.DELIVERY_PERSON_ID ,X.ICKEY /*상품코드*/ ,X.CFQTY /*확정수량*/ ,X.UOM /*수량단위*/ ,X.CLOSEYN /*마감여부*/ ,X.REPROCESSYN ,X.EXTERNORDERKEY /*외부주문번호*/ ,X.EXTERNORDERDETAILKEY /*외부주문상세번호*/ ,#{requestDt} /*요청일자*/ ,#{interfaceId} /*인터페이스 마스터 ID*/ ,#{sysdate} /*입력 일시*/ ,#{userid} /*입력 사용자 ID*/ ,#{sysdate} /*수정 일시*/ ,#{userid} /*수정 사용자 ID*/ FROM (
SELECT #{item.owkey} OWKEY ,#{item.soHdkey} SOHDKEY ,#{item.soDtkey} SODTKEY ,#{item.carrcd} CARRCD ,#{item.trpseqnum} TRPSEQNUM ,#{item.vehiclenum} VEHICLENUM ,#{item.dckey} DCKEY ,#{item.equiptypdesc} EQUIPTYPDESC ,#{item.deliveryPersonId} DELIVERY_PERSON_ID ,#{item.ickey} ICKEY ,#{item.cfqty} CFQTY ,#{item.uom} UOM ,#{item.closeyn} CLOSEYN ,#{item.reprocessyn} REPROCESSYN ,#{item.externorderkey} EXTERNORDERKEY ,#{item.externorderdetailkey} EXTERNORDERDETAILKEY
) X JOIN TORDER_INFO_SO_HD SH ON X.SOHDKEY = SH.SOHDKEY

mapper.update:
/* oms-socommon-sql-oracle.xml updateNisInfoSoDt */
UPDATE TORDER_INFO_SO_DT SET
NISYN = 'Y'
, NISQTY = #{nisqty}
, UPDATEDATE = #{interfaceDate}
, UPDATEURKEY = #{interfaceUrkey}
WHERE 1 = 1
AND SOHDKEY = #{sohdkey}
AND SODTKEY = #{sodtkey}

/* oms-socommon-sql-oracle.xml updateNisInfoSoHd */
UPDATE TORDER_INFO_SO_HD SET
NISYN = 'Y'
, UPDATEDATE = #{interfaceDate}
, UPDATEURKEY = #{interfaceUrkey}
WHERE 1 = 1
AND SOHDKEY = #{sohdkey}

mapper.select:
		/* oms-socommon-sql-oracle.xml selectOmsWkstatus */
        SELECT WKSTATUS
        FROM TORDER_INFO_SO_HD
        WHERE SOHDKEY = #{sohdkey}

	/* oms-socommon-sql-oracle.xml - selectNewOrderType */
	SELECT A.IBYN
	     , A.OBYN
	     , A.ORDERAT
	     , A.WMSYN
	     , A.WMSIBTYPE
	     , A.WMSOBTYPE
	  FROM TORDER_MST_ORTYPE A
	 WHERE A.OWKEY = #{owkey}
       AND A.ORDERTYPECD = #{ordertypecd}
